insert into public.lessons (job, difficulty, situation, correct, correct_ko, wrong1, wrong2, reason, is_premium) values
  ('marketer','기초','성과 보고 미팅에서 지난달 캠페인 결과를 팀에 공유하고 싶어요.','The campaign delivered strong results last month.',NULL,'The campaign did good results last month.','The campaign made good results last month.','''do results''는 비문이에요. ''deliver''는 성과나 결과를 달성하다는 의미의 비즈니스 표현이에요.',false),
  ('marketer','기초','성과 보고에서 전환율 변화를 수치로 설명하고 싶어요.','Our conversion rate increased by 15%.',NULL,'Our conversion rate is going up 15%.','Our conversion rate is going up with 15%.','''going up 15%''는 어색한 표현이에요. ''increased by + 수치''가 정확한 비즈니스 표현이에요.',false),
  ('marketer','기초','KPI 보고에서 목표 달성에 미치지 못했다고 솔직하게 말하고 싶어요.','We fell short of our target of 10,000 signups.',NULL,'We didn''t reach our goal of 10,000 signups.','We didn''t arrive our goal of 10,000 signups.','''fell short of''는 목표에 미달했다는 가장 자연스러운 비즈니스 표현이에요.',false),
  ('marketer','기초','동료에게 이메일로 보고서를 금요일까지 보내달라고 요청하고 싶어요.','Can you send me the report by Friday?',NULL,'Can you send me the report until Friday?','Can you send me the report before to Friday?','마감 기한에는 ''by''를 써요. ''until''은 그 시점까지 계속 지속되는 상황에 쓰는 표현이에요.',false),
  ('marketer','기초','동료에게 캠페인 계획에 대해 이야기하자고 미팅을 요청하고 싶어요.','I want to discuss the campaign plan.',NULL,'I want to discuss about the campaign plan.','I want to discuss on the campaign plan.','''discuss''는 타동사라서 전치사 없이 바로 목적어를 써요. ''discuss about''은 문법 오류예요.',false),
  ('marketer','기초','지난 분기 광고비 지출 내역을 팀에 보고하고 싶어요.','We spent a significant budget on ads last quarter.',NULL,'We spend a lot of money for ads last quarter.','We spending a lot of money for ads last quarter.','''spent''이 올바른 과거형이에요. ''significant budget on ads''가 비즈니스 맥락에서 더 자연스러운 표현이에요.',false),
  ('marketer','기초','금요일 오후에 미팅이 가능한지 동료에게 확인하고 싶어요.','Are you available this Friday afternoon?',NULL,'Are you free on this Friday afternoon?','Are you having time on this Friday afternoon?','비즈니스에서는 ''available''이 ''free''보다 공식적인 표현이에요. ''on this Friday''에서 ''on''은 생략하는 게 자연스러워요.',false),
  ('marketer','기초','미팅에서 광고 예산을 늘리자고 제안하고 싶어요.','I think we should increase the budget.',NULL,'I think we should to increase the budget.','I think we should increasing the budget.','''should'' 뒤에는 동사원형을 써요. ''to''는 필요 없어요.',false),
  ('marketer','기초','프로세스를 잘 모르는 외부 담당자에게 설명을 요청하고 싶어요.','Could you explain the process to me?',NULL,'Could you explain me the process?','Could you explain for me the process?','''explain''은 ''explain something to someone'' 구조로 써요. ''explain me''는 문법 오류예요.',false),
  ('marketer','기초','동료에게 광고 카피에 대한 피드백을 부탁하고 싶어요.','I''d love to get your feedback on this copy.',NULL,'Please give me your opinion about this copy.','Please tell me your opinion about this copy.','''feedback on''이 카피 리뷰 요청에 자연스러운 표현이에요. ''I''d love to''를 쓰면 공손한 인상을 줘요.',false),
  ('marketer','기초','미팅에서 동료의 의견에 동의를 표현하고 싶어요.','I agree with your point.',NULL,'I''m agree with your point.','I''m agreeing with your point.','''agree''는 동사라서 ''be동사 + agree'' 형태는 문법 오류예요. ''I agree''가 올바른 표현이에요.',false),
  ('marketer','기초','미팅에서 상대방의 제안 방향에 부드럽게 반대하고 싶어요.','I don''t think that''s the right approach.',NULL,'I don''t agree that idea.','I disagree about that idea.','직접 반대보다 ''I don''t think that''s the right approach''처럼 표현하면 비즈니스적으로 더 자연스러워요.',false),
  ('marketer','기초','다음 주로 미팅 일정을 변경하고 싶어요.','Can we reschedule the meeting to next week?',NULL,'Can we push the meeting to next week?','Can we move back the meeting to next week?','''reschedule''이 미팅 일정 변경의 표준 표현이에요. 전치사는 ''to''를 써요.',false),
  ('marketer','기초','작업이 완료되면 알려달라고 동료에게 요청하고 싶어요.','Please let me know when it''s ready.',NULL,'Please confirm to me when it''s ready.','Please tell to me when it''s ready.','''let me know''가 확인 요청에서 가장 자연스럽고 흔히 쓰는 표현이에요.',false),
  ('marketer','기초','협조해준 파트너에게 감사 인사를 전하고 싶어요.','Thank you for your cooperation.',NULL,'Thank you for your corporation.','Thank you for your collaborate.','''cooperation''은 협조, ''corporation''은 기업을 뜻해요. 두 단어를 혼동하지 않도록 주의하세요.',false),
  ('marketer','기초','동료에게 파일을 공유하겠다고 말하고 싶어요.','I''ll share the file with you.',NULL,'I will share you the file.','I will share to you the file.','''share''는 ''share A with B'' 구조로 써요. ''share you the file''은 문법 오류예요.',false),
  ('marketer','기초','광고 CTR 수치를 보고서에서 정확하게 표현하고 싶어요.','The CTR of the ad is 3.2%.',NULL,'The CTR of the ad is 3.2 percents.','The CTR of the ad are 3.2%.','퍼센트는 ''%'' 기호를 쓰거나 단수형 ''percent''를 써요. ''percents''는 비문이에요.',false),
  ('marketer','기초','발표를 마무리하며 핵심 내용을 정리하고 싶어요.','In summary, we met most of our targets.',NULL,'For summarize, we achieved most of our goals.','To conclude, we achieved most of our goals.','''For summarize''는 문법 오류예요. 전치사 뒤에는 동명사를 써야 해서 ''For summarizing''이 맞고, 발표 마무리에는 ''In summary''가 가장 자연스러운 표현이에요.',false),
  ('marketer','기초','팀 미팅에서 새로운 방향을 부드럽게 제안하고 싶어요.','Why don''t we try a new approach?',NULL,'Why don''t we try new approach?','Why don''t we trying new approach?','관사 ''a''가 필요해요. 어순은 ''Why don''t we + 동사원형''이에요.',false),
  ('marketer','기초','이메일에서 마감일을 정확하게 전달하고 싶어요.','The deadline is April 30th.',NULL,'The deadline is at April 30th.','The deadline will be on April 30th.','날짜 앞에는 ''at''이 아닌 ''on''을 써요. 비즈니스 이메일에서는 ''The deadline is April 30th''처럼 전치사를 생략하는 게 가장 간결하고 자연스러워요.',false),
  ('marketer','중급','A/B 테스트 결과를 팀에 비교해서 보고하고 싶어요.','Version A outperformed Version B by a significant margin.',NULL,'The A version performed better than B version.','Version A was better than Version B.','''outperformed by a significant margin''이 A/B 테스트 결과 보고에 더 정확하고 임팩트 있는 표현이에요.',false),
  ('marketer','중급','데이터 발표에서 참여율 상승 트렌드를 설명하고 싶어요.','The data indicates an upward trend in engagement.',NULL,'Our data shows an increasing trend.','Our data is showing an increasing trend.','''indicates''가 데이터 분석에 정확한 동사예요. ''upward trend in engagement''처럼 구체적으로 표현하는 게 좋아요.',false),
  ('marketer','중급','캠페인이 예상보다 저조한 성과를 냈다고 보고하고 싶어요.','The campaign underperformed against our projections.',NULL,'The campaign didn''t work as we planned.','The campaign was not successful as planned.','''underperformed against projections''가 목표 대비 결과를 전문적이고 객관적으로 설명하는 표현이에요.',false),
  ('marketer','중급','임원에게 캠페인의 투자 수익률을 설명하고 싶어요.','This campaign generated a 3x return on investment.',NULL,'This campaign has a good return.','This campaign shows good ROI.','구체적인 수치(3x)와 ''generated''를 함께 쓰면 임원 보고에서 훨씬 설득력 있어요.',false),
  ('marketer','중급','소셜 미디어 채널에 더 집중하자고 전략적으로 제안하고 싶어요.','I''d recommend shifting our focus toward social media channels.',NULL,'I suggest to focus more on social media.','I propose we focus more on social media.','''I''d recommend''가 제안할 때 공손하고 전문적인 표현이에요. ''shifting focus toward''는 전략적 변화를 잘 표현해요.',false),
  ('marketer','중급','다음 분기 예산 증액을 경영진에게 요청하고 싶어요.','We''re requesting an additional budget allocation for Q3 to scale high-performing campaigns.',NULL,'We need more budget for next quarter.','We need extra budget in the next quarter.','구체적인 이유(scale high-performing campaigns)를 포함한 예산 요청이 승인 가능성을 높여요.',false),
  ('marketer','중급','외부 파트너에게 협업 가능성을 타진하고 싶어요.','We''d love to explore a partnership opportunity with your team.',NULL,'We want to work together with your company.','We are interested to collaborate with your company.','''explore a partnership opportunity''가 외부 비즈니스 미팅에서 가장 전문적인 제안 표현이에요.',false),
  ('marketer','중급','캠페인 브리핑에서 이번 캠페인의 목표를 설명하고 싶어요.','The objective of this campaign is to drive user acquisition.',NULL,'The goal of this campaign is to get more users.','The purpose of this campaign is to increase users.','''objective''와 ''drive user acquisition''이 마케팅 전문 용어로 더 적합해요.',false),
  ('marketer','중급','프로젝트 우선순위를 논의할 때 이 건이 중요하다고 강조하고 싶어요.','I''d prioritize this initiative given its potential impact.',NULL,'I think this project is more important.','I think we should put this project first.','''prioritize''와 ''potential impact''이 우선순위 논의에서 가장 자연스러운 표현이에요.',false),
  ('marketer','중급','개발팀에 랜딩 페이지 작업 협조를 요청하고 싶어요.','Could we get some support from the dev team on the landing page build?',NULL,'Can the dev team help us with the landing page?','Can we ask dev team to help the landing page?','간접적이고 공손한 협업 요청이 팀 간 소통에서 더 자연스러워요.',false),
  ('marketer','중급','바운스율 상승 원인을 데이터로 신중하게 설명하고 싶어요.','The spike in bounce rate may be attributed to the design change.',NULL,'The bounce rate went up because of the new design.','The bounce rate increased because of the new design.','''may be attributed to''가 인과관계를 신중하게 표현하는 방식이에요. 데이터 발표에서는 단정보다 가능성 제시가 전문적이에요.',false),
  ('marketer','중급','발표 시작 시 Q2 마케팅 전략을 소개하고 싶어요.','Today I''d like to walk you through our Q2 marketing strategy.',NULL,'Today I will talk about our Q2 marketing plan.','Today I''ll present our Q2 marketing plan.','''walk you through''가 청중 친화적이고 발표 시작에 가장 자연스러운 표현이에요.',false),
  ('marketer','중급','동료의 피드백을 받아들이고 수정하겠다고 말하고 싶어요.','Thanks for the input — I''ll revise the copy accordingly.',NULL,'OK, I will change the copy.','OK, I''ll modify the copy.','''Thanks for the input''으로 피드백 수용 의사를 먼저 표현하는 게 비즈니스 에티켓이에요.',false),
  ('marketer','중급','현재 마감 일정이 너무 촉박하다고 재협상을 요청하고 싶어요.','The current timeline is challenging — could we discuss adjusting it?',NULL,'The deadline is too tight for us.','I don''t think we can finish by the deadline.','''The current timeline is challenging''이 직접 거절 없이 재협상을 요청하는 전문적인 표현이에요.',false),
  ('marketer','중급','트래픽 증가 수치를 보고서에서 정확하게 표현하고 싶어요.','Traffic grew 20% month-over-month, reaching X unique visitors.',NULL,'We got 20% more traffic than last month.','Traffic increased by 20% compared to last month.','''month-over-month''이 마케팅 리포트의 표준 표현이에요. 절대 수치를 함께 포함하면 더 설득력 있어요.',false),
  ('marketer','중급','광고 크리에이티브가 기대만큼 성과를 내지 못했다고 피드백하고 싶어요.','The ad creative isn''t resonating with our target audience as expected.',NULL,'The ad creative is not good enough.','The ad creative is not performing well.','구체적인 이유(not resonating with target audience)를 포함한 피드백이 개선 방향을 명확하게 해줘요.',false),
  ('marketer','중급','내일 캠페인 런칭 일정을 팀에 공지하고 싶어요.','We''re set to launch the campaign tomorrow — here''s what to expect.',NULL,'We will launch the campaign tomorrow.','The campaign launches tomorrow.','런칭 공지에 다음 액션(''here''s what to expect'')을 포함하면 팀 준비도를 높일 수 있어요.',false),
  ('marketer','중급','경쟁사 현황을 분석하고 대응 방안을 제시하고 싶어요.','Competitor X is gaining ground in our core segment — here''s how we can respond.',NULL,'Our competitor is doing better than us.','Our competitor performs better than us.','구체적인 경쟁사명과 대응 방향(''how we can respond'')을 포함한 분석이 더 전략적이에요.',false),
  ('marketer','중급','다음 캠페인의 타겟 오디언스를 구체적으로 설명하고 싶어요.','We should focus on the 25-34 demographic who are active on Instagram.',NULL,'We should target young people.','We should target the youth segment.','연령대와 플랫폼을 구체화한 타겟팅 제안이 실행 가능성을 높여요.',false),
  ('marketer','중급','발표 마무리에서 마케팅 성과를 총괄하여 정리하고 싶어요.','In summary, our marketing initiatives exceeded targets in three key areas.',NULL,'In conclusion, our marketing was successful.','Overall, our marketing was successful.','''exceeded targets in three key areas''처럼 구체적 근거를 포함한 결론이 훨씬 설득력 있어요.',false),
  ('marketer','중급','랜딩 페이지 작업에서 역할 분담을 제안하며 협업을 요청하고 싶어요.','I was hoping we could collaborate on the landing page — I''ll handle the copy if your team can take care of the design.',NULL,'I need your help with the landing page.','I want your team''s support for the landing page.','역할 분담을 명시한 협업 요청이 실행 가능성을 높여요.',false),
  ('marketer','중급','광고 예산 대비 성과가 좋았다는 것을 임원에게 설명하고 싶어요.','The investment was justified — we achieved a 4x ROAS against a projected 2x.',NULL,'We spent a lot, but results were good.','We spent much budget but we got good results.','''ROAS''와 구체적인 수치 비교(4x vs projected 2x)가 예산 정당화에 핵심 요소예요.',false),
  ('marketer','중급','캠페인에 문제가 발생했다고 빠르게 보고하고 싶어요.','We''ve identified an issue with the campaign that requires immediate attention.',NULL,'There is a problem with the campaign.','We found a problem in the campaign.','''requires immediate attention''이 긴박성을 전달하면서도 전문적인 이슈 보고 표현이에요.',false),
  ('marketer','중급','데이터를 근거로 영상 광고가 더 효과적이라고 제안하고 싶어요.','Based on our data, video ads tend to generate higher engagement in this segment.',NULL,'I think it''s better to use video ads.','Video ads would be more effective I think.','데이터 근거(''Based on our data'')를 포함한 의견 제시가 더 설득력 있어요.',false),
  ('marketer','중급','발표를 마치며 질문이 있는지 청중에게 물어보고 싶어요.','That covers everything on my end — does anyone have questions or concerns?',NULL,'That''s all I have to say.','I''ve finished my presentation.','''Does anyone have questions or concerns?''로 마무리하면 청중 참여를 유도하는 전문적인 발표 마무리가 돼요.',false),
  ('marketer','중급','광고 헤드라인을 메시지와 일치하도록 수정해달라고 요청하고 싶어요.','Could you revise the ad headline to better align with our messaging?',NULL,'Please change the headline of the ad.','Can you update the ad headline?','이유(''to better align with our messaging'')를 포함한 수정 요청이 더 효과적이에요.',false),
  ('marketer','중급','팀에 월말 마감 타임라인을 공유하고 싶어요.','We''re targeting end of month for delivery, with a checkpoint review on the 20th.',NULL,'We plan to finish by end of month.','We will complete this by end of month.','중간 체크포인트를 포함한 타임라인이 프로젝트 관리에 더 전문적이에요.',false),
  ('marketer','중급','오늘 중으로 성과 리포트를 보내겠다고 이메일로 알리고 싶어요.','I''ll have the performance report in your inbox by EOD.',NULL,'I''ll send the report today.','I''ll share the report today.','''in your inbox by EOD''(end of day)가 마케터 이메일 커뮤니케이션의 표준 표현이에요.',false),
  ('marketer','중급','여러 채널을 활용한 마케팅 전략을 소개하고 싶어요.','We employ an omni-channel approach, including paid social, SEO, and email.',NULL,'We use many channels for marketing.','We use multiple channels for marketing.','''omni-channel approach''와 구체적 채널 나열이 전략 발표에서 전문적인 표현이에요.',false),
  ('marketer','중급','우리 성과 지표가 업계 평균보다 높다는 것을 비교해서 말하고 싶어요.','Our metrics outpace industry benchmarks by roughly 15%.',NULL,'Our numbers are better than industry average.','Our results are better than the industry standard.','''outpace industry benchmarks''와 구체적 수치(15%)가 비교 보고에 더 정확한 표현이에요.',false),
  ('marketer','중급','A/B 테스트에서 B 버전이 더 높은 CTR을 달성했다고 보고하고 싶어요.','Variant B achieved a 23% higher CTR, making it the clear winner.',NULL,'Variant B got more clicks.','Variant B had more clicks than Variant A.','수치(23%)와 ''clear winner''로 의사결정을 돕는 표현이 테스트 리포트에 효과적이에요.',false),
  ('marketer','중급','이메일로 캠페인 성과 리포트를 공식적으로 공유하고 싶어요.','Please find attached the Q2 campaign performance report.',NULL,'Here is the campaign report.','I''m attaching the campaign report.','''Please find attached''가 공식 이메일에서 첨부 파일을 공유할 때 쓰는 표준 표현이에요.',false),
  ('marketer','중급','광고 디자인이 너무 복잡해서 개선이 필요하다고 피드백하고 싶어요.','The visual is a bit cluttered — simplifying it could improve click-through rates.',NULL,'The design is too complex.','The design has too many elements.','구체적인 개선 효과(improve CTR)를 포함한 피드백이 더 실행 가능한 방향을 제시해요.',false),
  ('marketer','중급','오디언스 세분화 방식을 팀에 설명하고 싶어요.','We segmented the audience into four distinct cohorts based on purchase intent.',NULL,'We divided our audience into groups.','We separated our audience into segments.','''segmented into cohorts based on purchase intent''이 마케팅 전문 용어로 더 정확한 표현이에요.',false),
  ('marketer','중급','유저 퍼널 구조와 전체 전환율을 설명하고 싶어요.','Users move through our funnel from awareness to conversion, with a ~5% overall conversion rate.',NULL,'Users come to our website and then buy.','Users visit our site and eventually make purchases.','퍼널 단계(awareness to conversion)와 전환율을 포함한 설명이 전문적이에요.',false),
  ('marketer','중급','SEO 성과를 개선할 여지가 있다고 제안하고 싶어요.','There''s significant room to improve our SEO performance, particularly around long-tail keywords.',NULL,'We can do better in SEO.','Our SEO can be improved.','''significant room to improve''와 구체적 방향(long-tail keywords)이 개선 제안에 효과적이에요.',false),
  ('marketer','중급','팀 전체에 프로젝트 현황을 업데이트하고 싶어요.','I''d like to bring everyone up to speed on where the project stands.',NULL,'I want to update everyone about the project.','I want to tell everyone about the project status.','''bring everyone up to speed''가 팀 업데이트를 시작할 때 쓰는 자연스러운 관용 표현이에요.',false),
  ('marketer','중급','캠페인 비용이 높지만 정당한 이유가 있다고 설명하고 싶어요.','The cost is on the higher side, but the targeting precision justifies the spend.',NULL,'The cost of this campaign is too high.','This campaign is more expensive than usual.','단순한 비용 언급이 아니라 정당화 이유(targeting precision)를 포함한 표현이 전문적이에요.',false),
  ('marketer','중급','매출 상승 원인을 분석하여 신중하게 설명하고 싶어요.','The uplift in sales is likely driven by our recent campaign and the seasonal demand.',NULL,'Sales went up because of our campaign.','Our campaign caused sales to increase.','''likely driven by''로 복합 요인을 고려한 신중한 분석 표현이에요.',false),
  ('marketer','중급','다음 분기 유저 성장 목표를 구체적으로 설정하고 공유하고 싶어요.','Our Q3 goal is to grow our user base by 20%, with a focus on organic acquisition.',NULL,'Our goal for next quarter is more users.','We want to get more users next quarter.','수치(20%)와 방법(organic acquisition)을 포함한 목표 설정이 더 전문적이에요.',false),
  ('marketer','중급','에이전시 미팅에서 캠페인 전략 방향을 바꾸자고 제안하고 싶어요.','We''d like to discuss pivoting the campaign strategy to better align with current market trends.',NULL,'We want to change the direction of the campaign.','We need to change the campaign strategy.','''pivoting the strategy to align with market trends''가 전략 변경을 제안하는 세련된 표현이에요.',false),
  ('marketer','중급','에이전시가 제출한 결과물이 브리프와 다르다고 피드백하고 싶어요.','This doesn''t quite match the brief — let me walk you through the key areas we''d like to revisit.',NULL,'This isn''t what we wanted.','This is different from what we requested.','구체적인 다음 단계(''walk you through key areas'')를 포함한 피드백이 더 생산적이에요.',false),
  ('marketer','중급','파트너에게 데이터 공유 협업을 제안하고 싶어요.','We''d be open to a data-sharing arrangement that could benefit both parties.',NULL,'We can share data with you.','We are willing to share data with you.','''arrangement that benefits both parties''가 파트너십 제안에서 상호이익을 강조하는 표현이에요.',false),
  ('marketer','중급','런칭 준비가 완료됐다고 팀에 확인시켜주고 싶어요.','We''re on track for launch — all assets are approved and the team is briefed.',NULL,'Everything is ready for the launch.','We finished preparing for the launch.','구체적인 완료 항목(assets approved, team briefed)을 포함한 확인이 더 명확해요.',false),
  ('marketer','중급','캠페인 런칭 날짜가 변경됐다고 이유와 함께 공지하고 싶어요.','We''re pushing the launch date back to [DATE] to allow time for final QA.',NULL,'We are changing the campaign launch date.','The launch date has been changed.','변경 이유(final QA)를 포함한 공지가 팀의 이해를 높여요.',false),
  ('marketer','중급','목표를 거의 달성했지만 100%는 아니었다고 보고하고 싶어요.','We came close to our target, finishing at 92% of the Q2 goal.',NULL,'We almost reached our goal.','We nearly achieved our Q2 goal.','구체적 수치(92%)를 포함한 성과 보고가 더 투명하고 신뢰감을 줘요.',false),
  ('marketer','중급','데이터에서 흥미로운 인사이트를 발견해 팀과 공유하고 싶어요.','The data reveals an interesting pattern — users who engage with video content are 3x more likely to convert.',NULL,'I found something interesting in the data.','I found an interesting data insight.','구체적인 수치와 인사이트를 바로 제시하는 방식이 더 설득력 있어요.',false),
  ('marketer','중급','이메일 채널이 가장 높은 ROI를 낸다고 보고하고 싶어요.','Email remains our top-performing channel, consistently driving the highest ROI.',NULL,'Email marketing is working well for us.','Email marketing has good performance.','''top-performing channel''과 ''highest ROI''를 포함한 채널 평가가 더 전문적이에요.',false),
  ('marketer','중급','다음 단계 액션 아이템을 팀에 명확하게 공유하고 싶어요.','Our next steps are to analyze the data, refine targeting, and scale the top-performing ads.',NULL,'Now we need to do the next things.','Next, we have to do several tasks.','구체적인 액션 아이템 나열이 ''next steps'' 커뮤니케이션의 표준이에요.',false),
  ('marketer','중급','이번 캠페인이 전반적으로 성공적이었다고 총평하고 싶어요.','Overall, the campaign exceeded expectations — hitting 110% of our KPIs and delivering strong brand lift.',NULL,'Overall, the campaign was a success.','The campaign generally performed well.','구체적인 성과 지표(110% of KPIs, brand lift)를 포함한 총평이 훨씬 설득력 있어요.',false),
  ('marketer','고급','임원에게 마케팅 전략의 정량적 성과를 보고하고 싶어요.','Our marketing strategy is yielding measurable results, with a 25% YoY improvement in customer acquisition cost.',NULL,'Our marketing strategy is working.','Our marketing efforts have been successful.','YoY 지표와 구체적 수치를 포함한 임원 보고가 더 신뢰감을 줘요.',false),
  ('marketer','고급','이번 분기 성과를 근거로 예산 증액을 경영진에게 요청하고 싶어요.','I''d like to make the case for a budget increase, given the strong ROAS we''ve demonstrated this quarter.',NULL,'We need more budget to grow.','We should have a larger budget for growth.','''make the case for''가 임원진 설득에서 논리적 근거를 강조하는 표현이에요.',false),
  ('marketer','고급','리텐션 중심 성장 모델로의 전략 전환을 경영진에게 발표하고 싶어요.','We''re proposing a strategic pivot — shifting from broad acquisition to a retention-first growth model.',NULL,'We will change our marketing strategy.','We plan to update our marketing strategy.','''strategic pivot''과 구체적 방향(retention-first)이 전략 발표의 임팩트를 높여요.',false),
  ('marketer','고급','캠페인 실행 리스크를 구체적으로 언급하며 주의를 환기시키고 싶어요.','There''s execution risk here, particularly around creative fatigue and audience saturation.',NULL,'This campaign might not work.','This campaign has some risks.','구체적인 리스크 요인(creative fatigue, audience saturation)을 명시한 표현이 더 전문적이에요.',false),
  ('marketer','고급','경쟁사 압박에 단순히 반응하는 게 아닌 선제적 대응이 필요하다고 말하고 싶어요.','We need to develop a proactive response to the competitive pressure, rather than simply reacting.',NULL,'We need to react to what our competitors are doing.','We should respond to competitor moves.','''proactive response vs simply reacting''의 대비가 전략적 사고를 보여주는 표현이에요.',false),
  ('marketer','고급','새 오디언스 세그먼트가 기존보다 더 나은 성과를 낼 것이라고 예측하고 싶어요.','My hypothesis is that the new audience segment will outperform the existing cohort by at least 15%.',NULL,'I think the new audience will perform better.','The new audience should do better.','''My hypothesis is that''과 구체적 수치 예측이 데이터 드리븐 마케터의 표현이에요.',false),
  ('marketer','고급','복합적인 결과를 강약을 구분해 균형 있게 설명하고 싶어요.','The results are nuanced — while we exceeded reach targets, conversion efficiency was below benchmark.',NULL,'The results are mixed.','We had some good and some bad results.','''nuanced''와 구체적인 강/약 대비가 복합적인 결과를 전문적으로 설명하는 표현이에요.',false),
  ('marketer','고급','브랜드 마케팅 투자가 장기적으로 퍼포먼스 마케팅에도 도움이 된다고 내부 설득하고 싶어요.','Investing in brand equity now will compound our performance marketing returns over time.',NULL,'We should focus on brand, not just performance.','Brand is also important, not just performance.','장기적 복리 효과(compound returns)를 강조한 표현이 내부 설득에 효과적이에요.',false),
  ('marketer','고급','경영진 발표에서 결과를 Q3 전략과 연결해 소개하고 싶어요.','I''ll take you through the key findings and what they mean for our Q3 strategy.',NULL,'I''ll show you our results today.','I''ll present today''s campaign results.','결과를 전략과 연결하는 발표 시작이 경영진에게 더 임팩트 있어요.',false),
  ('marketer','고급','저조한 성과의 캠페인을 바로 중단하지 않고 원인 분석 후 결정하자고 제안하고 싶어요.','Given the underperformance, I recommend pausing the campaign and conducting a root cause analysis before reallocating the budget.',NULL,'The campaign is failing. We need to stop it.','The campaign isn''t working and we should stop it.','즉각 중단이 아닌 근본 원인 분석(RCA) 이후 결정을 제안하는 표현이 더 전략적이에요.',false),
  ('marketer','고급','TikTok을 신규 채널로 소규모 테스트부터 시작하자고 제안하고 싶어요.','I''d recommend piloting TikTok as a growth channel, starting with a limited test budget to validate performance before scaling.',NULL,'We should try TikTok.','We should start using TikTok for marketing.','''piloting with limited test budget before scaling''이 신규 채널 도입 시 리스크 관리 전략을 보여줘요.',false),
  ('marketer','고급','매출 상승의 원인을 캠페인과 외부 요인으로 구분해 분석하고 싶어요.','While our campaign likely contributed to the sales uplift, we need to account for external factors like seasonality and the product launch.',NULL,'Our campaign increased sales.','The sales increase was because of our campaign.','귀인 분석에서 외부 요인을 고려하는 표현이 더 정확하고 신뢰성이 높아요.',false),
  ('marketer','고급','마지막 클릭 어트리뷰션 대신 증분성 테스트 기반 채널 믹스 최적화를 제안하고 싶어요.','We should optimize our channel mix based on incrementality testing rather than last-click attribution.',NULL,'We need to use more channels.','We should diversify our marketing channels.','''incrementality testing vs last-click attribution''이 고급 마케팅 측정 방법론을 이해하는 표현이에요.',false),
  ('marketer','고급','팀원별 역할을 명확히 분담해 책임감과 실행 속도를 높이고 싶어요.','I''d like each team member to own a specific workstream — this will improve accountability and execution speed.',NULL,'Let''s all work together on this.','Everyone should collaborate on this project.','''own a specific workstream''과 ''accountability'' 강조가 팀 리더십 표현에 효과적이에요.',false),
  ('marketer','고급','데이터 결과가 긍정적이지만 샘플 크기 한계를 솔직하게 언급하고 싶어요.','The data suggests positive results, though the sample size limits our statistical confidence.',NULL,'Our data shows the campaign worked.','The campaign data looks positive.','''sample size limits statistical confidence''가 데이터 해석의 한계를 전문적으로 표현하는 방식이에요.',false),
  ('marketer','고급','CPC 안정을 가정한 다음 분기 리드 성장 예측을 보고하고 싶어요.','Based on current trends, we''re projecting a 20% QoQ growth in leads, assuming stable CPC.',NULL,'I think next quarter will be good.','Next quarter should show growth.','구체적인 가정(stable CPC)을 포함한 예측 보고가 신뢰도를 높여요.',false),
  ('marketer','고급','C레벨 업데이트에서 Q2 결과와 하반기 전략 임플리케이션을 함께 전달하고 싶어요.','Q2 results exceeded plan, driven by email and paid social — I''ll focus on what this means for our H2 strategy.',NULL,'Here are our Q2 results.','Let me share our Q2 performance.','임원 보고에서 결과와 전략 임플리케이션을 동시에 연결하는 표현이 효과적이에요.',false),
  ('marketer','고급','신규 피처 출시에 맞춰 마케팅 메시지를 조율하자고 프로덕트팀에 제안하고 싶어요.','I''d like to align with the product team to ensure our messaging is consistent with the upcoming feature release.',NULL,'We need the product team''s help.','We should work with the product team.','''align to ensure messaging consistency''가 마케팅-프로덕트 협업의 구체적 목적을 잘 표현해요.',false),
  ('marketer','고급','이 캠페인이 회사 OKR과 직접 연결된다는 것을 강조하고 싶어요.','This initiative directly supports our company OKR of increasing net revenue retention by 10%.',NULL,'This campaign supports our company goals.','This campaign aligns with our company objectives.','''directly supports OKR''과 구체적 지표(10% NRR)로 전략적 연계를 명확히 표현해요.',false),
  ('marketer','고급','전략 문서에서 타겟팅 근거와 예산 배분에 대한 검토를 요청하고 싶어요.','I''d appreciate your review of the strategy document — particularly the targeting rationale and budget allocation.',NULL,'Please check my work.','Could you review this document?','검토 요청 시 구체적인 포인트(targeting rationale, budget allocation)를 명시하면 효율적이에요.',false),
  ('marketer','고급','콘텐츠 마케팅 투자 증액이 장기적으로 CAC를 낮출 수 있다고 설득하고 싶어요.','Content marketing has a proven track record of reducing CAC over time — a 30% increase in content investment could yield long-term efficiency gains.',NULL,'We should invest more in content marketing.','Content marketing is worth investing in.','구체적 지표(CAC)와 수치(30%), 장기 효과를 포함한 설득이 가장 임팩트 있어요.',false),
  ('marketer','고급','미디어 바잉 비용을 연간 지출 규모를 근거로 협상하고 싶어요.','Given our projected annual spend with your platform, I''d like to discuss a volume-based pricing structure.',NULL,'Can we negotiate the media buy price?','Can we get a discount on media buying?','''volume-based pricing structure''가 단순 할인 요청보다 전문적인 협상 표현이에요.',false),
  ('marketer','고급','복합적인 결과를 채널, 오디언스, 크리에이티브별로 나누어 설명하고 싶어요.','The results are multifaceted — I''ll break down performance by channel, audience, and creative to give a full picture.',NULL,'The results are complicated to explain.','The results need more detailed explanation.','''multifaceted''와 구체적 분석 방식(by channel, audience, creative)을 예고하는 표현이 발표에 효과적이에요.',false),
  ('marketer','고급','클릭 기반 지표에서 비즈니스 성과 중심 KPI로 측정 체계를 전환하자고 제안하고 싶어요.','We''re evolving our measurement framework from click-based metrics to business outcome-driven KPIs.',NULL,'We''re going to change how we measure success.','We will change our metrics and KPIs.','''evolving from click-based to business outcome-driven''이 측정 체계 전환을 전략적으로 표현하는 방식이에요.',false),
  ('marketer','고급','양사 오디언스를 활용한 코마케팅을 제안하고 싶어요.','I''d like to propose a co-marketing initiative that leverages both our audiences for mutual growth.',NULL,'We can do co-marketing together.','We should try co-marketing with your brand.','''leverages both audiences for mutual growth''가 파트너십 가치를 구체적으로 설명하는 표현이에요.',false),
  ('marketer','고급','예산 삭감 상황에서 ROI가 높은 채널에 자원을 집중하자고 제안하고 싶어요.','With the reduced budget, I''d recommend focusing resources on our highest-ROI channels and pausing experimental spend.',NULL,'We can''t do everything with less budget.','We''ll have to reduce our marketing activities.','삭감 상황에서 자원 집중 전략을 제시하는 표현이 리더십을 보여줘요.',false),
  ('marketer','고급','어트리뷰션이 어렵다는 점을 인정하면서 멀티터치 모델 도입을 제안하고 싶어요.','Attribution remains a challenge — I recommend a multi-touch model to more accurately reflect the customer journey.',NULL,'We can''t tell exactly which channel drove sales.','It''s hard to know which channel caused the sales.','구체적 솔루션(multi-touch attribution)을 제안하는 표현이 문제 제기만 하는 것보다 전문적이에요.',false),
  ('marketer','고급','내년 마케팅 연간 계획을 회사 성장 목표와 연결해 발표하고 싶어요.','This is our annual marketing roadmap, aligned to our company''s growth objectives and prioritized by expected ROI.',NULL,'This is our marketing plan for next year.','I''ll present next year''s marketing strategy.','''roadmap aligned to growth objectives, prioritized by ROI''가 연간 계획 발표에 임팩트 있는 표현이에요.',false),
  ('marketer','고급','글로벌 확장 시장을 오가닉 수요 신호 데이터를 기반으로 선정하고 싶어요.','We''re evaluating international expansion, starting with markets that show organic demand signals for our product.',NULL,'We want to expand to other countries.','We plan to go global with our marketing.','''organic demand signals''를 기반으로 한 데이터 드리븐 글로벌 전략 표현이에요.',false),
  ('marketer','고급','마케팅팀의 장기 비전을 경영진에게 임팩트 있게 전달하고 싶어요.','Our vision is to build a best-in-class marketing function that drives compounding growth and brand equity over the long term.',NULL,'We want to be the best marketing team.','We aim to become an excellent marketing team.','''best-in-class'', ''compounding growth'', ''brand equity''를 포함한 장기 비전 표현이 가장 임팩트 있어요.',false),
  ('designer','기초','디자인 리뷰 중 동료에게 내 작업에 대한 피드백을 요청하고 싶어요.','Can I get feedback on this?',NULL,'Can I get a feedbacks on this?','Can I get some feedbacks on this?','''feedback''은 불가산 명사라서 복수형 ''s''를 붙이거나 관사 ''a''를 쓰면 안 돼요.',false),
  ('designer','기초','디자인 리뷰에서 내가 만든 디자인을 팀에 순서대로 소개하고 싶어요.','I''ll walk you through the designs I made.',NULL,'I will show you the designs what I made.','I will show you the designs that I made.','''walk you through''는 순서대로 안내할 때 쓰는 발표 필수 표현이에요. 목적격 관계대명사는 생략이 가장 자연스러워요.',false),
  ('designer','기초','이전 버전보다 이번 버전이 더 개선됐다고 설명하고 싶어요.','This version is better than the previous one.',NULL,'This version is more better than before.','This version is much better than the old one.','''more better''는 이중비교급 오류예요. ''better'' 자체가 비교급이라서 ''more''를 붙일 필요가 없어요.',false),
  ('designer','기초','디자인 리뷰에서 상대방이 한 말의 의미를 좀 더 자세히 설명해달라고 요청하고 싶어요.','Can you walk me through what you mean?',NULL,'Can you explain me what you mean?','Can you explain to me what do you mean?','''explain me''는 문법 오류예요. ''explain to me''가 맞고, 간접의문문은 평서문 어순으로 써요.',false),
  ('designer','중급','플로우 전반에 대한 의견을 동료에게 부드럽게 요청하고 싶어요.','I''d love to get your input on this flow.',NULL,'I want to get your inputs about this flow.','I want to get your input about this flow.','''input''은 피드백 의미로 쓸 때 불가산 명사예요. ''on this flow''가 ''about''보다 더 구체적인 표현이에요.',false),
  ('designer','중급','디자인 리뷰에서 내 디자인이 상대방이 기대했던 방향과 맞는지 확인하고 싶어요.','Does this design meet what you had in mind?',NULL,'Does this design hit the mark of what you expected?','Does this design hit what you had in mind?','''meet what you had in mind''가 상대방의 기대를 확인하는 가장 자연스러운 표현이에요.',false),
  ('designer','중급','디자인에 대한 팀원의 의견을 듣고 싶다고 말하고 싶어요.','I''d like to hear your thoughts on this.',NULL,'I''d like to hear your thought on this.','I''d like to hear your thinking on this.','''thoughts''는 복수형으로 써야 해요. ''your thinking''은 어색한 표현이에요.',false),
  ('designer','고급','디자인 리뷰에서 내가 내린 주요 결정들을 순서대로 설명하고 싶어요.','Let me take you through the key decisions I made.',NULL,'Let me take you to the key decisions I made.','Let me walk through the key decisions I took.','''take you through''가 설명하며 안내하는 올바른 표현이에요. ''take you to''는 장소로 이동하는 뜻이에요.',false),
  ('designer','고급','이번 이터레이션이 사용자 피드백을 바탕으로 진행됐다고 설명하고 싶어요.','This iteration was informed by user feedback.',NULL,'This iteration was informed from user feedback.','This iteration was informed with user feedback.','''informed by''가 올바른 전치사 조합이에요. ''informed from''과 ''informed with''는 비문이에요.',false),
  ('designer','고급','리뷰어에게 날카로운 피드백이 있으면 부드럽게 공유해달라고 요청하고 싶어요.','I''d appreciate any critical feedback you might have.',NULL,'I''d appreciate it if you can share critical thoughts.','I''d appreciate it if you could share critical thoughts.','''I''d appreciate + 명사''가 가장 간결하고 세련된 표현이에요. 가정법에서는 ''can''이 아닌 ''could''를 써요.',false),
  ('designer','기초','동료의 디자인에서 아이콘이 어울리지 않는다고 부드럽게 말하고 싶어요.','This icon doesn''t quite work here.',NULL,'This icon is not so good.','This icon is not working well.','직접 비판 대신 ''doesn''t quite work''처럼 완곡하게 표현하는 게 영어 비즈니스 피드백 스타일이에요.',false),
  ('designer','기초','버튼 크기가 너무 크다고 구체적으로 피드백하고 싶어요.','I think this button is a bit too large.',NULL,'I think this button is too much big.','I think this button is too much large.','''too much + 형용사''는 문법 오류예요. ''too + 형용사'' 구조가 올바르고 ''large''가 디자인 용어로 더 적합해요.',false),
  ('designer','중급','텍스트 가독성이 떨어진다고 피드백하고 싶어요.','The typography feels a bit hard to read.',NULL,'The typography is a bit hard to see.','The typography is slightly hard to look.','텍스트는 ''read''가 ''see''보다 적합한 표현이에요. ''hard to look''은 ''look at''으로 써야 해요.',false),
  ('designer','중급','요소 간 간격이 일관성이 없다고 피드백하고 싶어요.','The spacing between elements feels inconsistent.',NULL,'The spacing between elements feel inconsistent.','The spacing between elements are feeling inconsistent.','주어 ''spacing''은 단수라서 ''feels''가 올바른 동사예요. ''are feeling''은 수일치 오류예요.',false),
  ('designer','중급','CTA 버튼이 더 눈에 띄도록 수정해달라고 요청하고 싶어요.','Can you make the CTA button stand out more?',NULL,'Can you make the CTA button more standout?','Can you make the CTA button more outstanding?','''stand out''은 동사구예요. ''make + 목적어 + 동사원형'' 구조를 써야 해요.',false),
  ('designer','중급','디자인이 조금 더 다듬어져야 한다고 말하고 싶어요.','I feel this needs a little more polish.',NULL,'I feel this needs little more polish.','I feel this needs little more polishing.','''a little more''가 올바른 표현이에요. ''little''만 쓰면 ''거의 없다''는 반대 의미가 돼요.',false),
  ('designer','고급','비주얼 계층 구조를 개선해야 한다고 피드백하고 싶어요.','The visual hierarchy is something we should address.',NULL,'The visual hierarchy is something we should address on.','The visual hierarchy is what we should address on.','''address''는 타동사라서 ''on'' 없이 바로 목적어를 써요. ''address on''은 비문이에요.',false),
  ('designer','고급','내비게이션의 명확성이 부족하다고 디자인 피드백을 주고 싶어요.','This design lacks clarity in the navigation.',NULL,'This design lacks of clarity in the navigation.','This design is lacking of clarity in navigation.','''lack''은 타동사라서 ''of'' 없이 바로 목적어를 써요. ''lacks of''는 비문이에요.',false),
  ('designer','고급','이 방향이 완전히 확신이 서지 않는다고 솔직하게 말하고 싶어요.','I''m not entirely convinced this direction is right.',NULL,'I''m not entirely convince this direction is right.','I''m not entirely convincing about this direction.','수동의 의미로 ''convinced''(과거분사)를 써야 해요. ''convince''는 현재형, ''convincing''은 능동 의미예요.',false),
  ('designer','고급','온보딩 관련 결정을 다시 검토해볼 수 있는지 제안하고 싶어요.','Could we revisit the decision we made around onboarding?',NULL,'Could we revisit the decision we made on onboarding?','Could we revisit the decision on onboarding we made?','''around onboarding''이 범위를 포괄하는 더 자연스러운 표현이에요. 관계절은 수식 명사 바로 뒤에 붙여요.',false),
  ('designer','기초','시안 발표에서 단순하게 만드는 데 집중했다고 설명하고 싶어요.','I focused on keeping it simple.',NULL,'I focused to make it simple.','I was focusing to simplify it.','''focus on + -ing''가 올바른 구조예요. ''focus to''는 비문이에요.',false),
  ('designer','기초','히스토리 확인이 필요한 유저를 위해 이 화면을 설계했다고 설명하고 싶어요.','I designed this screen for users who want to check their history.',NULL,'I designed this screen for the case when users want to check history.','I designed this screen for users want to check their history.','관계절 ''who want to''로 자연스럽게 연결해요. ''for the case when''은 어색한 번역투예요.',false),
  ('designer','기초','메인 컬러를 파란색으로 변경했다고 발표에서 설명하고 싶어요.','I changed the main color to blue.',NULL,'The main color is changed to blue.','The main color was changed into blue color.','발표 맥락에서는 능동태 ''I changed''가 주체를 명확히 해서 더 자연스러워요.',false),
  ('designer','중급','앱을 처음 열었을 때 유저가 보게 되는 화면이라고 설명하고 싶어요.','This screen is what users see when they first open the app.',NULL,'This screen is for when users first open the app.','This screen appears for when users first open the app.','''what users see when''이 화면의 목적을 명확하게 설명하는 표현이에요. ''for when''은 어색해요.',false),
  ('designer','중급','새 온보딩 플로우를 단계별로 소개하고 싶어요.','Let me walk you through the new onboarding flow.',NULL,'Let me brief you about the new onboarding flow.','Let me brief you on the new onboarding flow.','''walk you through''가 발표에서 단계별로 안내하는 가장 자연스러운 표현이에요.',false),
  ('designer','중급','발표 시작 시 오늘 보여줄 내용을 간략히 소개하고 싶어요.','Here''s what I''ll be presenting today.',NULL,'Here''s what I''m going to present you today.','Here''s what I am presenting to you today.','''presenting today''가 간결하고 자연스러워요. ''present to you today''는 문법적이지만 길고 딱딱해요.',false),
  ('designer','고급','미적 요소와 사용성 사이에서 균형을 맞추려 했다고 설명하고 싶어요.','I''ve tried to strike a balance between aesthetics and usability.',NULL,'I''ve tried to balance aesthetics with usability.','I''ve tried to make a balance of aesthetics with usability.','''strike a balance between A and B''가 관용 표현이에요. ''balance + 목적어''는 ''between''을 쓰지 않아요.',false),
  ('designer','고급','이 디자인 패턴이 Material Design에서 영감을 받았다고 설명하고 싶어요.','This design pattern was inspired by Material Design.',NULL,'This design pattern was inspired from Material Design.','This design pattern got inspiration from Material Design.','''inspired by''가 올바른 전치사 조합이에요. ''inspired from''은 비문이에요.',false),
  ('designer','고급','이 결정의 배경 논거가 노트에 정리돼 있다고 설명하고 싶어요.','The rationale behind this decision is explained in the notes.',NULL,'The rationale behind this decision are explained in the notes.','The rationale behind this decision are being explained in notes.','''rationale''은 단수 명사라서 ''is''가 올바른 동사예요. ''are''는 수일치 오류예요.',false),
  ('designer','고급','이번 리디자인에 유저 중심 접근 방식을 적용했다고 발표하고 싶어요.','I took a user-centered approach to this redesign.',NULL,'I took an user-centered approach for this redesign.','I took user-centered approach for this redesign.','''user''는 자음 발음이라서 ''a user-centered''가 맞아요. ''approach to''가 ''approach for''보다 자연스러운 전치사예요.',false),
  ('designer','기초','개발자에게 내가 보낸 스펙 파일을 확인해달라고 요청하고 싶어요.','Please check the spec file I sent.',NULL,'Please check the spec file what I sent.','Please check the spec file that I sended.','목적격 관계대명사 생략이 가장 자연스러워요. ''send''의 과거형은 ''sent''예요. ''sended''는 없는 단어예요.',false),
  ('designer','기초','애니메이션에 몇 가지 문제가 있다고 개발자에게 알리고 싶어요.','There are some issues with the animation.',NULL,'There is some issues with the animation.','There have some issues with animation.','''issues''는 복수 명사라서 ''there are''를 써요. ''there have''는 비문이에요.',false),
  ('designer','기초','에셋을 Figma에 업로드했다고 개발자에게 알리고 싶어요.','I''ll upload the assets to Figma.',NULL,'I will upload the assets on Figma.','I will upload the assets in Figma.','업로드는 방향성이 있어서 ''to''를 써요. ''on Figma''는 위치를 나타내는 전치사로 여기선 어색해요.',false),
  ('designer','중급','구현을 마치면 알려달라고 개발자에게 요청하고 싶어요.','Can you let me know when you''ve finished implementing this?',NULL,'Can you let me know when you finish to implement this?','Can you let me know when you finish implementing this?','''finish + -ing''가 올바른 구조예요. ''when you''ve finished''가 완료 시점을 가장 자연스럽게 표현해요.',false),
  ('designer','중급','컴포넌트가 예상대로 렌더링되지 않는다고 개발자에게 전달하고 싶어요.','The component isn''t rendering as expected.',NULL,'The component is not rendering like as expected.','The component is not rendering as like expected.','''as expected''가 관용 표현이에요. ''like as''와 ''as like''는 둘 다 비문이에요.',false),
  ('designer','중급','내가 공유한 스펙에 맞게 패딩을 조정해달라고 요청하고 싶어요.','Could you align the padding to match the specs I shared?',NULL,'Could you align the padding to match the specs which I shared?','Could you align padding to match with the specs I shared?','목적격 관계대명사 생략이 자연스러워요. ''match''는 타동사라서 ''with'' 없이 바로 목적어를 써요.',false),
  ('designer','고급','호버 상태가 부드럽게 전환돼야 한다고 개발자에게 전달하고 싶어요.','The hover state should transition smoothly.',NULL,'The hover state should be transitioned smoothly.','The hover state needs to be transitioned in a smooth way.','능동태 ''should transition''이 더 간결하고 자연스러워요. 피동형 표현은 불필요하게 복잡해요.',false),
  ('designer','고급','엔지니어가 추측하지 않아도 되도록 스펙에 주석을 달겠다고 말하고 싶어요.','I''ll annotate the specs so engineers don''t have to guess.',NULL,'I''ll annotate the specs so engineers don''t need to guess.','I''ll annotate the specs so that engineers don''t need guessing.','''don''t have to''가 ''don''t need to''보다 자연스러운 표현이에요. ''need guessing''은 비문이에요.',false),
  ('designer','고급','서로 같은 방향으로 이해하고 있는지 개발자와 확인하고 싶어요.','Let''s sync up to make sure we''re on the same page.',NULL,'Let''s sync up to make sure we''re both in the same page.','Let''s sync up to make sure we have the same page.','''on the same page''가 올바른 관용 표현이에요. ''in the same page''는 전치사 오류예요.',false),
  ('designer','고급','이 인터랙션이 조금 더 다듬어져야 한다고 개발자에게 전달하고 싶어요.','I think this interaction could use a bit more refinement.',NULL,'I think this interaction needs to be refined a bit further.','I think this interaction needs refining further a bit.','''could use''는 개선이 필요하다는 세련된 표현이에요. ''more further''는 이중비교급 오류예요.',false),
  ('designer','기초','리서치 결과에서 앱 사용이 어렵다는 유저 피드백을 공유하고 싶어요.','Users are saying the app is hard to use.',NULL,'Users are saying that the app is difficult to use it.','Users said that the app is difficult to use it.','''to use it''에서 ''it''은 중복 목적어예요. ''hard to use''가 더 간결하고 자연스러운 표현이에요.',false),
  ('designer','기초','지난주에 5명의 유저와 유저 테스트를 진행했다고 보고하고 싶어요.','We ran user testing with 5 users last week.',NULL,'We did user testing with 5 users last week.','We made user testing with 5 users last week.','''run user testing''이 자연스러운 콜로케이션이에요. ''an user''는 오류로 ''a user''가 맞아요.',false),
  ('designer','중급','유저들이 앱 내에서 자신의 위치를 파악하지 못하는 경향이 있다고 공유하고 싶어요.','Users tend to lose track of where they are in the app.',NULL,'Users tend to lose where they are in the app.','Users often lose themselves where they are in the app.','''lose track of''가 위치 파악을 못하다는 의미의 올바른 관용 표현이에요.',false),
  ('designer','중급','인터뷰가 12명의 참여자와 함께 진행됐다고 보고하고 싶어요.','The interview was conducted with 12 participants.',NULL,'The interview was conducted to 12 participants.','The interview was conducted for 12 participants.','인터뷰 참여자에는 ''with''를 써요. ''by''는 진행자, ''to/for''는 전치사 오류예요.',false),
  ('designer','중급','유저들이 가장 많이 언급한 페인 포인트가 내비게이션 혼란이라고 공유하고 싶어요.','The pain point users mentioned most is confusing navigation.',NULL,'The pain point users mentioned most is about confusing navigation.','The pain points users mentioned most is confusing navigation.','''is + 명사구''가 깔끔한 구조예요. ''is about''은 중복이에요. 주어 ''pain point''는 단수라서 ''is''가 맞아요.',false),
  ('designer','고급','유저 피드백을 바탕으로 얻은 인사이트를 공유하고 싶어요.','Based on user feedback, we''ve gained valuable insights into user behavior.',NULL,'Based on user feedback, we''ve gained valuable insights into user behaviors.','Based on users feedback, we''ve gained valuable insights into user behavior.','''behavior''는 불가산 명사라서 단수형을 써요. ''users feedback''는 소유격 오류로 ''user feedback''이 맞아요.',false),
  ('designer','고급','사용성 테스트 결과에서 유저들이 특정 태스크 완료에 어려움을 겪었다고 보고하고 싶어요.','The usability test revealed that users struggled to complete this task.',NULL,'The usability test has revealed that users struggled to complete this task.','The usability test revealed that users were struggling on this task.','완료된 연구 결과 보고에는 단순 과거형이 맞아요. ''struggling on''은 전치사 오류예요.',false),
  ('designer','고급','결제 화면에서 유저들이 이탈하는 패턴을 발견했다고 공유하고 싶어요.','We''re seeing a pattern where users drop off at the payment screen.',NULL,'We''re seeing a pattern that users drop off at the payment screen.','We''re seeing a pattern which users drop off at the payment screen.','장소나 상황을 나타낼 때는 ''where''가 자연스러워요. ''which users drop off''는 관계사 오류예요.',false),
  ('designer','고급','리서치를 통해 발견한 핵심 유저 니즈를 이 기능이 해결한다고 설명하고 싶어요.','This feature addresses a core user need we identified in research.',NULL,'This feature addresses a core user need we identified on research.','This feature addresses core user needs which we''ve identified on research.','''in research''가 올바른 전치사 구조예요. ''on research''는 비문이에요.',false),
  ('designer','고급','리서치 결과가 초기 가설과 일치한다고 발표하고 싶어요.','The findings align well with what we hypothesized earlier.',NULL,'The findings align well with what we''ve assumed earlier.','The findings align well with what we''ve been assuming earlier.','''hypothesized''가 리서치 맥락에서 더 전문적인 표현이에요. ''been assuming earlier''는 시제 오류예요.',false),
  ('designer','기초','팀에 디자인 시스템의 간격 일관성 유지를 요청하고 싶어요.','We should keep the spacing consistent.',NULL,'We should use consistent the spacing.','We should use the spacing consistently.','''keep + 목적어 + 형용사''가 올바른 구조예요. ''consistent''는 형용사라서 부사 자리에 쓸 수 없어요.',false),
  ('designer','기초','이 컴포넌트가 디자인 가이드라인과 일치해야 한다고 말하고 싶어요.','We need to align this with our design guidelines.',NULL,'We need to align this with our design guideline.','We should follow the design guideline of ours.','''guidelines''가 복수형으로 일반적이에요. ''of ours''는 어색한 이중소유격이에요.',false),
  ('designer','중급','이 컴포넌트가 디자인 토큰을 따르지 않는다고 지적하고 싶어요.','This component doesn''t follow our design tokens.',NULL,'This component doesn''t follow our design token.','This component doesn''t follow the design token of ours.','''design tokens''는 복수형이 일반적이에요. ''of ours''는 이중소유격 오류예요.',false),
  ('designer','중급','아이콘 크기와 스타일이 일관되어야 한다고 팀에 전달하고 싶어요.','Let''s make sure all icons are consistent in size and style.',NULL,'Let''s make sure all icons are consistent in size and the style.','Let''s make sure all icons are consistent in size and in the style.','병렬 구조에서 ''size and style''로 관사 없이 통일하는 게 자연스러워요.',false),
  ('designer','중급','이 컴포넌트를 개발자 참조용으로 문서화해두어야 한다고 말하고 싶어요.','We should document this component for future developer reference.',NULL,'We should document this component for future reference of developers.','We should document this component for future references of developers.','''for future developer reference''가 간결한 관용 표현이에요. ''references''는 이 맥락에서 불가산 명사예요.',false),
  ('designer','고급','이 패턴이 시스템 전반의 일관성을 깨고 있다고 지적하고 싶어요.','This pattern breaks the consistency we''ve established throughout the system.',NULL,'This pattern breaks the consistency we established through the system.','This pattern disrupts the consistency established by us throughout the system.','''throughout''이 시스템 전체를 아우를 때 적합해요. ''through''는 단순히 통과하는 의미예요.',false),
  ('designer','고급','컴포넌트 라이브러리의 오래된 패턴을 감사해야 한다고 제안하고 싶어요.','The component library needs to be audited for outdated patterns.',NULL,'The component library needs auditing for the outdated patterns.','The component library needs to audit for outdated patterns.','수동태 ''needs to be audited''가 올바른 구조예요. ''needs to audit''은 라이브러리가 직접 감사하는 의미라서 오류예요.',false),
  ('designer','고급','오래된 버튼 스타일을 이번 분기 안에 폐기하자고 제안하고 싶어요.','We should deprecate the old button styles by end of quarter.',NULL,'We should depreciate the old button styles by end of quarter.','We should deprecate the old button styles by the end of this quarter.','''deprecate''는 기술 용어로 폐기하다는 뜻이에요. ''depreciate''는 가치가 하락하다는 전혀 다른 단어예요.',false),
  ('designer','고급','이 문제를 디자인 부채로 플래깅하고 다음 스프린트에서 처리하자고 말하고 싶어요.','I''ll flag this as design debt to address in a future sprint.',NULL,'I''ll flag this as a design debt to be addressed in the future sprint.','I''ll flag this as a design debt for addressing in future sprint.','''design debt''는 관사 없이 쓰는 전문 용어예요. ''to address''가 ''to be addressed''보다 간결하고 자연스러워요.',false),
  ('designer','고급','이 패턴이 기존 모달과 동일한 문제를 해결한다고 설명하고 싶어요.','This pattern solves the same problem our existing modal does.',NULL,'This pattern solves the same problem that our existing modal does.','This pattern solves the same problem our existing modal solved.','동일 비교에서 ''the same ... as''가 관용 표현이에요. 관계사를 생략하는 게 더 자연스러워요.',false),
  ('designer','기초','개발자에게 Figma 파일 링크를 보내겠다고 말하고 싶어요.','I''ll send you the Figma file link.',NULL,'I will send you the link for Figma file.','I will send to you the link of Figma.','''send you + 목적어''가 기본 구조예요. ''link for''는 전치사 오류이고 ''send for''는 비문이에요.',false),
  ('designer','기초','에셋을 Figma에 업로드했다고 개발팀에 알리고 싶어요.','I uploaded the files to Figma.',NULL,'I uploaded the files on Figma.','I uploaded files in Figma.','업로드는 방향성이 있어서 ''to''를 써요. ''on Figma''는 위치 전치사로 여기서는 어색해요.',false),
  ('designer','중급','핸드오프 시 인터랙션에 주석을 달았다고 개발자에게 알리고 싶어요.','I''ve annotated the interactions so devs know how they work.',NULL,'I''ve marked all the interactions with notes so devs know how it works.','I''ve noted the interactions so that devs can know how it works.','''annotate''가 핸드오프 맥락에서 정확한 전문 표현이에요. ''marked with notes''는 어색한 중복이에요.',false),
  ('designer','중급','레드라인이 스펙 파일에 포함돼 있다고 말하고 싶어요.','The redlines are included in the spec file.',NULL,'The redlines are included inside the spec file.','Redlines are included into the spec file.','''included in''이 가장 자연스러운 표현이에요. ''inside''는 물리적 내부를 강조하고 ''into''는 움직임의 전치사예요.',false),
  ('designer','중급','이 컴포넌트가 디자인과 맞는지 개발자에게 확인해달라고 요청하고 싶어요.','Can you check if this matches the design?',NULL,'Can you check if this is match to the design?','Can you check if this is matched with the design?','''matches''가 올바른 동사 형태예요. ''is match to''는 비문이고 ''is matched with''는 수동태 오용이에요.',false),
  ('designer','고급','핵심 디자인 결정을 담은 핸드오프 문서를 준비했다고 말하고 싶어요.','I''ve prepared a handoff document outlining the key design decisions.',NULL,'I''ve prepared a handoff document outlining all the design decisions.','I''ve prepared a handoff documentation outlining all design decisions.','''key design decisions''가 ''all the design decisions''보다 실용적이에요. ''handoff documentation''은 어색하고 ''document''이 맞아요.',false),
  ('designer','고급','스펙에 대해 추가 설명이 필요하면 알려달라고 말하고 싶어요.','Let me know if you need any clarification on the spec.',NULL,'Let me know if you need any clarifications regarding the spec.','Let me know if there''s anything you need to clarify about the spec.','''clarification''은 불가산 명사라서 단수형을 써요. ''on the spec''이 ''regarding''보다 간결해요.',false),
  ('designer','고급','엔지니어가 쉽게 탐색할 수 있도록 Figma 파일을 구성했다고 말하고 싶어요.','I''ve set up the Figma file so it''s easy for engineers to navigate.',NULL,'I''ve set up the Figma file so it''s easily for engineers to navigate.','I''ve set up the Figma file for engineers to navigate easily.','''easily''는 부사라서 형용사 자리에 올 수 없어요. ''so it''s easy for ... to navigate''가 가장 명확한 표현이에요.',false),
  ('designer','고급','모든 에셋이 일관된 네이밍 컨벤션을 따르도록 정리했다고 말하고 싶어요.','I''ve made sure all assets follow a consistent naming convention.',NULL,'I''ve made sure all assets are named with a consistent naming convention.','I''ve made sure all assets are named consistently with the naming convention.','''follow a naming convention''이 자연스러운 표현이에요. ''named with a naming convention''은 어색한 중복이에요.',false),
  ('designer','고급','구현 전에 컴포넌트 스펙을 꼭 참조해달라고 요청하고 싶어요.','Please refer to the component specs before starting implementation.',NULL,'Please refer the component specs before starting implementation.','Please reference the component specs before starting the implementation.','''refer to''가 올바른 표현이에요. ''refer''는 자동사라서 반드시 ''to''가 필요해요.',false),
  ('designer','기초','스테이크홀더 미팅에서 디자인 방향에 대해 논의하고 싶다고 말하고 싶어요.','We need to discuss the design direction.',NULL,'We need to discuss about the design direction.','We should have a discussion about the design directions.','''discuss''는 타동사라서 ''about'' 없이 바로 목적어를 써요. ''discuss about''은 문법 오류예요.',false),
  ('designer','기초','미팅에서 제안된 방향에 동의하지 않는다고 말하고 싶어요.','I don''t agree with this direction.',NULL,'I''m not agree with this direction.','I''m not agreed with this direction.','''agree''는 동사라서 ''be동사 + agree'' 구조는 오류예요. ''I don''t agree''가 올바른 부정형이에요.',false),
  ('designer','중급','스테이크홀더 우려 사항을 기록하고 후속 조치를 취하겠다고 말하고 싶어요.','Let me note your concern and follow up.',NULL,'Let me take note of your concern and follow back.','Let me take note of your concern and get back to you.','''follow up''이 올바른 관용 표현이에요. ''follow back''은 SNS 맞팔 의미예요.',false),
  ('designer','중급','지난 미팅 이후 상당한 진전이 있었다고 보고하고 싶어요.','We''ve made significant progress since the last meeting.',NULL,'We''ve made significant progress since the last meet.','We''ve made significant progress from the last meeting.','''meeting''이 올바른 명사예요. ''meet''는 동사이고 비격식 명사예요. ''since''에 관사가 필요해요.',false),
  ('designer','중급','이 방향이 경영진이 설정한 프로덕트 비전과 일치한다고 설명하고 싶어요.','This aligns with the product vision leadership has set.',NULL,'This aligns with the product vision that leadership had set.','This aligns with the product vision that leadership has set.','현재 완료 ''has set''이 아직 유효한 비전을 표현해요. 관계사를 생략하면 더 자연스러워요.',false),
  ('designer','고급','최신 디자인 현황을 스테이크홀더 전체에 공유하고 싶어요.','I''d like to bring everyone up to speed on the latest designs.',NULL,'I''d like to bring everyone up to speed with the latest designs.','I''d like to speed everyone up on the latest designs.','''bring up to speed on''이 관용 표현이에요. ''up to speed with''는 전치사 오류예요.',false),
  ('designer','고급','미팅 시작 전 이번 세션의 목표를 팀과 공유하고 싶어요.','Before we dive in, I want to align on the goals for this session.',NULL,'Before we dive in, I want to align us on the goals of this session.','Before we dive in, I want to align everyone around goals of this session.','''align on''이 관용 표현이에요. ''align us on''에서 ''us''는 불필요하고 ''around goals''는 전치사 오류예요.',false),
  ('designer','고급','타임라인에 영향을 줄 수 있는 리스크를 스테이크홀더에게 알리고 싶어요.','I want to flag a risk that could impact our timeline.',NULL,'I want to flag a risk that could impact on our timeline.','I want to flag a potential risk that could impact on the timeline.','''impact''는 타동사라서 ''on'' 없이 바로 목적어를 써요. ''impact on''은 문법 오류예요.',false),
  ('designer','고급','진행하기 전에 방향에 대한 합의를 이끌어내고 싶어요.','Can we get consensus on the direction before moving forward?',NULL,'Can we get consensus of the direction before moving forward?','Can we reach a consensus about the direction before moving forward?','''consensus on''이 올바른 전치사예요. ''get consensus on''이 ''reach a consensus about''보다 간결해요.',false),
  ('designer','고급','피드백에 감사를 표하고 이를 반영하겠다고 말하고 싶어요.','I appreciate the feedback — I''ll take that on board and get back to you.',NULL,'I appreciate the feedback — let me take that on board and come back to you.','I appreciate the feedback — I''ll take it on board and get back to you with updates.','''take on board''는 수용하다는 관용 표현이에요. ''get back to you''가 ''come back to you''보다 더 자연스러워요.',false),
  ('designer','기초','피드백을 반영해 디자인을 수정하겠다고 말하고 싶어요.','I''ll revise it based on your feedback.',NULL,'I will revise it base on your feedback.','I will revise it basing on your feedback.','''based on''은 항상 고정된 전치사구예요. ''base on''이나 ''basing on''은 오류예요.',false),
  ('designer','기초','이번 디자인이 더 단순해야 한다고 의견을 제시하고 싶어요.','I think we need a simpler design.',NULL,'I think we need more simple design.','I think the design should be more simpler.','비교급 ''simpler''가 자연스러워요. ''more simpler''는 이중비교급 오류예요. 관사 ''a''도 필요해요.',false),
  ('designer','중급','수정된 화면을 다시 한번 검토해달라고 요청하고 싶어요.','Can you take another look at this revised screen?',NULL,'Can you give a second look to this revised screen?','Can you give another look to this revised screen?','''take another look at''이 관용 표현이에요. ''give a look to''는 어색한 전치사 구조예요.',false),
  ('designer','중급','논의한 내용을 바탕으로 디자인을 업데이트했다고 말하고 싶어요.','I''ve updated the design based on our discussion.',NULL,'I''ve updated the design according to what we discussed.','I''ve updated the design as per the discussion we had.','''based on our discussion''이 가장 자연스럽고 간결한 표현이에요. ''as per''는 지나치게 격식적이에요.',false),
  ('designer','중급','이 디자인을 완성하려면 한 라운드가 더 필요하다고 말하고 싶어요.','I''ll need one more round to nail this down.',NULL,'I''ll need one more round for nailing this down.','I''ll need another round of iteration to nail this down.','''to + 동사원형''이 목적을 나타내는 올바른 구조예요. ''for nailing''은 전치사 오류예요.',false),
  ('designer','고급','지난주 피드백 대부분을 이번 버전에 반영했다고 말하고 싶어요.','I''ve incorporated most of the feedback from last week.',NULL,'I''ve incorporated most of the feedbacks from last week.','I''ve incorporated most of feedbacks received last week.','''feedback''은 불가산 명사예요. ''feedbacks''는 비문이고 ''most of feedbacks''는 관사 누락이에요.',false),
  ('designer','고급','이번 이터레이션에서 이전에 놓쳤던 엣지 케이스를 처리했다고 말하고 싶어요.','This iteration addresses the edge cases that were previously overlooked.',NULL,'This iteration addresses the edge cases that were overlooked prior.','This iteration addresses edge cases which were overlooked before.','''previously overlooked''이 가장 자연스러운 표현이에요. ''prior''를 단독 부사로 쓰면 어색해요.',false),
  ('designer','고급','최종 확정 전에 이 디자인을 다양한 각도로 검토해보고 싶다고 말하고 싶어요.','I want to pressure-test this design before we call it final.',NULL,'I want to pressure-test this design before we call it as final.','I want to pressure-test this design before calling it to final.','''call it final''이 관용 표현이에요. ''call it as final''과 ''calling it to final''은 비문이에요.',false),
  ('designer','고급','아이디어를 시각화하기 위해 빠르게 와이어프레임을 만들어보겠다고 말하고 싶어요.','I''ll take a stab at a quick wireframe to visualize the idea.',NULL,'I''ll take a stab to create a quick wireframe to visualize the idea.','I''ll take a quick stab at wireframing the idea.','''take a stab at + 명사/-ing''가 관용 표현이에요. ''take a stab to create''는 전치사 오류예요.',false),
  ('designer','고급','확정 전에 검토할 수 있도록 몇 가지 옵션을 준비하겠다고 말하고 싶어요.','Let me put together a few options for you to vet before we commit.',NULL,'Let me put together a few options for you to check before we''ll commit.','Let me put a few options together for your vetting before we commit.','시간 부사절에서 ''will''은 쓰지 않아요. ''for your vetting''은 어색한 명사구예요.',false),
  ('designer','기초','팀 미팅에서 동료에게 의견을 물어보고 싶어요.','Let me know what you think.',NULL,'Let me know what you think it.','Let me know what do you think.','''what you think''는 간접의문문으로 평서문 어순을 써요. ''think it''은 중복 목적어예요.',false),
  ('designer','기초','팀 미팅에서 프로젝트 타임라인에 대해 질문하고 싶어요.','I have a question about the project timeline.',NULL,'I have a question about the timeline of this project.','I have some question about the project timeline.','''project timeline''이 자연스러운 복합 명사예요. ''some question''은 단수 명사에 어색해요.',false),
  ('designer','중급','팀 미팅에서 특정 안건을 다음 미팅으로 미루자고 제안하고 싶어요.','Can we table this topic for the next meeting?',NULL,'Can we postpone this topic to the next meeting?','Can we delay this topic until the next meeting?','''table this topic''이 미루다는 비즈니스 관용 표현이에요. ''put off to''는 전치사 오류로 ''put off until''이 맞아요.',false),
  ('designer','중급','유저 플로우를 내가 맡겠다고 팀에게 말하고 싶어요.','I''ll take ownership of the user flow.',NULL,'I''m going to take the lead on the user flow.','I''m going to own the user flow.','''take ownership''이 책임감을 강조하는 비즈니스 표현이에요. ''own''은 여기서 덜 자연스러워요.',false),
  ('designer','중급','팀 미팅 후 해당 내용을 검토하고 의견을 정리해서 공유하겠다고 말하고 싶어요.','I''ll look into this and get back to you with my thoughts.',NULL,'I''ll have a look at this and come back with my thoughts.','I''ll look at this and come back to you with my thoughts later.','''look into''가 적극적으로 검토하다는 의미예요. ''get back to you''가 ''come back with''보다 자연스러운 표현이에요.',false),
  ('designer','고급','팀 미팅에서 스코프 크립 리스크가 있다고 경고하고 싶어요.','I think we''re at risk of scope creep here.',NULL,'I think we''re in a risk of scope creep here.','I think there''s a risk of scope creep happening here.','''at risk of''가 관용 표현이에요. ''in a risk of''는 비문이에요.',false),
  ('designer','고급','팀이 같은 방향으로 일하고 있는지 확인하고 싶어요.','Let''s make sure we''re all pulling in the same direction.',NULL,'Let''s make sure we''re all rowing in the same direction.','Let''s make sure everyone is pulling towards the same direction.','''pulling in the same direction''이 관용 표현이에요. ''rowing''은 비표준이고 ''towards the same direction''은 전치사 중복이에요.',false),
  ('designer','고급','과도하게 복잡하게 접근하지 말고 집중하자고 팀에 말하고 싶어요.','I don''t want us to boil the ocean here — let''s stay focused.',NULL,'I don''t want us to boil the ocean here — let''s keep focused.','I don''t want to boil the ocean here — let''s all stay focused.','''boil the ocean''은 과도하게 복잡하게 하다는 관용 표현이에요. ''stay focused''가 ''keep focused''보다 자연스러워요.',false),
  ('designer','고급','지금 한 발 물러서서 큰 그림을 보자고 팀에게 제안하고 싶어요.','This is a good opportunity to step back and look at the bigger picture.',NULL,'This is a good opportunity to step back and think about the bigger picture.','This is a good opportunity to take a step back and consider the bigger picture.','''look at the bigger picture''가 관용 표현이에요. ''think about''도 맞지만 ''look at''이 더 자연스러워요.',false),
  ('designer','고급','단순함이 항상 최선이라는 가정에 의문을 제기하고 싶어요.','I''d like to challenge the assumption that simplicity always wins.',NULL,'I''d like to challenge the assumption where simplicity always wins.','I''d like to question the assumption of simplicity always winning.','동격절에는 ''that''을 써요. ''where''는 장소나 상황절에 쓰이고 ''assumption of ... winning''은 어색한 명사구예요.',false),
  ('developer','기초','코드 리뷰에서 동료 코드에 성능 문제가 있다고 지적하고 싶어요.','This could cause performance issues.',NULL,'This code is making performance problems.','Performance is not good in this.','''could cause''는 단정 짓지 않고 문제를 지적하는 가장 자연스러운 방식이에요.',false),
  ('developer','기초','코드 리뷰에서 동료에게 왜 이 방식을 선택했는지 물어보고 싶어요.','Can you explain why you chose this approach?',NULL,'Why did you do it like this?','I cannot understand this code.','기술적 결정의 이유를 묻는 가장 정중하고 자연스러운 표현이에요.',false),
  ('developer','기초','코드 리뷰에서 이 부분을 리팩토링하자고 제안하고 싶어요.','I think we should refactor this part.',NULL,'We must refactor this immediately.','Refactoring is needed by us.','''I think we should''는 강요 없이 제안하는 가장 부드러운 표현이에요.',false),
  ('developer','기초','코드 리뷰에서 변수 이름이 너무 모호하다고 피드백하고 싶어요.','This variable name is a bit unclear.',NULL,'This variable name is not so good.','Variable name doesn''t quite make sense.','''a bit unclear''가 직접 비판보다 부드럽고 구체적인 피드백 표현이에요.',false),
  ('developer','기초','코드 리뷰에서 엣지 케이스를 처리해야 한다고 말하고 싶어요.','We should also handle edge cases here.',NULL,'You forgot to handle edge cases.','Edge cases are not handled in this.','''We should''로 함께 해결한다는 뉘앙스를 주는 게 협업적인 코드 리뷰 표현이에요.',false),
  ('developer','중급','코드 리뷰에서 이 로직이 더 단순화될 수 있다고 제안하고 싶어요.','This logic could be simplified a bit.',NULL,'This logic is too much complex.','This code is overly complicated to read.','''could be simplified''가 개선을 부드럽게 제안하는 코드 리뷰 표현이에요. ''too much complex''는 문법 오류예요.',false),
  ('developer','중급','코드 리뷰에서 테스트 커버리지가 부족하다고 지적하고 싶어요.','The test coverage here looks insufficient.',NULL,'There is no enough test coverage here.','Tests are not enough in this section.','''looks insufficient''가 테스트 부족을 객관적으로 표현하는 방식이에요. ''no enough''는 문법 오류예요.',false),
  ('developer','중급','코드 리뷰에서 이 함수가 너무 많은 역할을 한다고 지적하고 싶어요.','This function is doing too many things.',NULL,'This function is doing too much things.','This function has too much responsibilities.','''too many things''가 셀 수 있는 것의 올바른 표현이에요. ''too much things''와 ''too much responsibilities''는 문법 오류예요.',false),
  ('developer','고급','코드 리뷰에서 이 패턴이 향후 유지보수를 어렵게 할 수 있다고 경고하고 싶어요.','This pattern could make future maintenance more difficult.',NULL,'This pattern will cause problems in future.','This will be hard to maintain in the future.','''could make future maintenance more difficult''가 구체적이고 전문적인 코드 리뷰 피드백이에요.',false),
  ('developer','고급','코드 리뷰에서 이 구현이 요구사항과 완벽히 일치하는지 확인해달라고 요청하고 싶어요.','Could you verify this aligns with all the requirements?',NULL,'Please check if this is meeting all the requirements properly.','Can you double check if requirements are met here?','''verify this aligns with''가 요구사항 확인 요청에 가장 전문적인 표현이에요.',false),
  ('developer','기초','기술 토론에서 이 라이브러리가 우리 프로젝트에 적합한지 의견을 제시하고 싶어요.','I''m not sure this library is the right fit for our use case.',NULL,'I think this library is not good for us.','This library doesn''t seem good enough for us.','''not the right fit for our use case''가 기술 선택에서 적합성을 평가하는 표준 표현이에요.',false),
  ('developer','기초','기술 토론에서 이 접근 방식의 장단점을 살펴보자고 제안하고 싶어요.','Let''s weigh the trade-offs of this approach.',NULL,'Let''s talk about the goods and bads of this approach.','Let''s talk about good and bad points of this.','''goods and bads''는 영어에서 쓰지 않는 표현이에요. ''weigh the trade-offs''가 기술 토론에서 장단점을 평가한다는 의미를 가장 정확하게 전달하는 표현이에요.',false),
  ('developer','중급','기술 토론에서 현재 아키텍처로는 확장하기 어렵다고 설명하고 싶어요.','Our current architecture may struggle to scale under increased load.',NULL,'Our current architecture is not scalable enough.','The architecture can''t handle more traffic.','''may struggle to scale under increased load''가 확장성 문제를 신중하게 표현하는 방식이에요.',false),
  ('developer','중급','기술 토론에서 기술 부채를 해결해야 한다고 주장하고 싶어요.','The technical debt here is becoming a bottleneck — I think we should prioritize addressing it.',NULL,'We have too much technical debt to ignore.','We must fix all the technical debt right now.','문제의 영향(''bottleneck'')과 해결 제안을 함께 표현하는 것이 더 설득력 있어요.',false),
  ('developer','중급','기술 토론에서 이 솔루션이 장기적으로 더 나은 선택이라고 설명하고 싶어요.','This solution offers better long-term maintainability, even if the initial setup takes more time.',NULL,'This solution is better in the long run.','This approach is more future-proof.','장기적 이점과 단기적 비용을 함께 표현하는 것이 기술 결정에서 더 설득력 있어요.',false),
  ('developer','중급','기술 토론에서 두 가지 접근 방식을 비교해 설명하고 싶어요.','We have two main approaches here — let me walk you through the trade-offs of each.',NULL,'There are two ways we can do this.','There are two options and both have good and bad points.','''walk you through the trade-offs''가 기술 비교 설명에 가장 적합한 표현이에요.',false),
  ('developer','고급','기술 토론에서 마이크로서비스 전환의 복잡성을 설명하고 싶어요.','Migrating to a microservices architecture introduces significant operational complexity.',NULL,'Moving to microservices will be very complex.','Microservices architecture is too complicated for us now.','''introduces significant operational complexity''가 기술 전환 비용을 전문적으로 표현하는 방식이에요.',false),
  ('developer','고급','기술 토론에서 이 API 설계가 RESTful 원칙을 따르지 않는다고 지적하고 싶어요.','This API design deviates from RESTful conventions in a few key areas.',NULL,'This API design is not following proper REST principles.','This API doesn''t follow REST properly.','''deviates from RESTful conventions in key areas''가 구체적이고 전문적인 표현이에요.',false),
  ('developer','고급','기술 토론에서 캐싱 전략을 도입하면 응답 속도가 크게 개선될 것이라고 제안하고 싶어요.','Implementing a caching layer here could significantly reduce response times.',NULL,'We should add caching to make things faster.','If we cache this, it will be much faster.','''implementing a caching layer''와 ''reduce response times''가 기술 제안에 더 정확한 표현이에요.',false),
  ('developer','고급','기술 토론에서 이 설계 결정이 시스템 전체에 영향을 줄 수 있다고 경고하고 싶어요.','This architectural decision has broad implications across the entire system — we should align the team before proceeding.',NULL,'This decision will affect many parts of the system.','This is a big decision that affects everything.','영향 범위와 팀 합의의 필요성을 함께 표현하는 것이 더 전문적이에요.',false),
  ('developer','기초','데일리 스탠드업에서 오늘 진행할 작업을 팀에 공유하고 싶어요.','I''m working on the new API integration today.',NULL,'I am doing API things today.','My task is about API integration.','현재 진행형으로 구체적인 작업을 간결하게 전달하는 게 스탠드업 최적 표현이에요.',false),
  ('developer','기초','스탠드업에서 어제 작업이 완료됐다고 공유하고 싶어요.','I wrapped up the authentication module yesterday.',NULL,'I finished the task of yesterday.','Yesterday''s task is done by me.','''wrapped up''이 완료를 자연스럽게 표현하는 비즈니스 표현이에요. 구체적인 작업명을 언급하는 게 좋아요.',false),
  ('developer','기초','스탠드업에서 오늘 작업이 막혀있다고 알리고 싶어요.','I''m blocked on the deployment issue — I could use some help.',NULL,'I am blocked and can''t do work today.','There is a blocker and I need help.','구체적으로 어디서 막혔는지와 도움 요청을 함께 표현하는 것이 스탠드업 표준이에요.',false),
  ('developer','중급','스프린트 플래닝에서 이 태스크의 예상 작업량이 너무 크다고 말하고 싶어요.','This task seems too large to fit in one sprint — should we break it down?',NULL,'This task is too big to do in one sprint.','We cannot complete this task in one sprint.','문제 제기와 함께 분해 제안을 자연스럽게 연결하는 표현이에요.',false),
  ('developer','중급','스프린트 리뷰에서 이번 스프린트에서 완료한 작업을 설명하고 싶어요.','This sprint, we completed the user authentication flow and the dashboard redesign.',NULL,'We did all the things in this sprint.','We have done the work for this sprint.','구체적인 완료 항목을 나열하는 것이 스프린트 리뷰의 표준 표현이에요.',false),
  ('developer','중급','스프린트 회고에서 앞으로 개선할 점을 제안하고 싶어요.','One thing we could improve next sprint is our PR review turnaround time.',NULL,'We should do better next sprint.','Next sprint we must improve many things.','구체적인 개선 항목을 제시하는 것이 회고에서 더 생산적인 표현이에요.',false),
  ('developer','중급','스프린트 플래닝에서 이 기능의 우선순위를 높여야 한다고 제안하고 싶어요.','I''d suggest bumping this feature up in priority given the upcoming release.',NULL,'I think this feature is more important than other things.','This feature should have higher priority.','''bumping up in priority given''이 우선순위 변경을 근거와 함께 제안하는 자연스러운 표현이에요.',false),
  ('developer','고급','스프린트 플래닝에서 이번 스프린트의 기술 부채 해소에 시간을 할당하자고 제안하고 싶어요.','I''d recommend allocating some capacity this sprint for addressing our highest-priority tech debt.',NULL,'We should spend some time on technical debt this sprint.','We must handle technical debt in this sprint.','''allocating capacity for addressing tech debt''이 스프린트 플래닝에서 더 전문적인 표현이에요.',false),
  ('developer','고급','스프린트 리뷰에서 목표를 달성하지 못한 이유를 설명하고 싶어요.','We fell short of our sprint goal due to an unexpected infrastructure outage mid-sprint.',NULL,'We couldn''t finish because there were many problems.','The sprint goal was not achieved because of issues.','구체적인 이유(infrastructure outage)를 포함한 설명이 팀의 신뢰도를 높여요.',false),
  ('developer','고급','스프린트 플래닝에서 이 태스크의 의존성 때문에 다음 스프린트로 미뤄야 한다고 말하고 싶어요.','This task is blocked by a dependency on the data pipeline work — I''d suggest deferring it to the next sprint.',NULL,'We can''t do this task because of dependencies.','This task depends on other work and should be moved to next sprint.','의존성의 구체적인 내용과 대안 제시를 함께 표현하는 것이 더 전문적이에요.',false),
  ('developer','기초','버그를 발견했다고 팀에 알리고 싶어요.','I''ve spotted a bug in the checkout flow — I''ll file a ticket.',NULL,'I found a bug in the code.','There is a bug that I discovered.','버그 위치와 후속 조치를 함께 표현하는 것이 더 전문적인 버그 보고 방식이에요.',false),
  ('developer','기초','버그가 어떤 환경에서 재현됐는지 설명하고 싶어요.','This bug is reproducible only in the production environment with iOS 16.',NULL,'The bug happens only in some cases.','The bug can be seen in production sometimes.','재현 조건(환경, OS 버전)을 구체적으로 명시하는 것이 버그 리포트의 표준이에요.',false),
  ('developer','중급','이 버그가 사용자에게 미치는 영향을 설명하고 싶어요.','This bug is blocking users from completing checkout, which directly impacts revenue.',NULL,'This bug is affecting users badly.','Users can''t do things because of this bug.','영향 범위와 비즈니스 임팩트를 함께 표현하는 것이 버그 우선순위 결정에 중요해요.',false),
  ('developer','중급','버그 수정이 생각보다 복잡해서 시간이 더 필요하다고 알리고 싶어요.','The root cause is deeper than expected — fixing this will take an additional day.',NULL,'This bug is hard to fix and needs more time.','Fixing this bug will take longer time than we thought.','근본 원인(''root cause'')과 추가 소요 시간을 구체적으로 표현하는 것이 더 전문적이에요.',false),
  ('developer','중급','이 버그가 다른 기능에도 영향을 줄 수 있다고 경고하고 싶어요.','This bug may have a wider impact — it could affect the payment and notification modules as well.',NULL,'This bug might also affect other features.','Other parts of the system might also have this bug.','영향받을 수 있는 모듈을 구체적으로 명시하는 것이 더 전문적인 버그 분석이에요.',false),
  ('developer','중급','버그를 임시 방편으로 처리했다고 팀에 알리고 싶어요.','I''ve applied a temporary workaround — we should revisit this with a proper fix in the next sprint.',NULL,'I did a quick fix for this bug for now.','I fixed it temporarily but it needs real fix later.','''temporary workaround''와 후속 조치 계획을 함께 표현하는 것이 전문적인 엔지니어링 커뮤니케이션이에요.',false),
  ('developer','고급','이 버그의 근본 원인을 분석한 결과를 팀에 공유하고 싶어요.','The root cause analysis points to a race condition in the session management module.',NULL,'I found why this bug happened.','This bug was caused by problems in session management.','''root cause analysis''와 기술적 원인(''race condition'')을 명확히 표현하는 것이 RCA 리포트의 표준이에요.',false),
  ('developer','고급','이 버그가 특정 조건에서만 발생하는 재현이 어려운 버그임을 설명하고 싶어요.','This is an intermittent bug — it only surfaces under high concurrency conditions.',NULL,'This bug is difficult to find and reproduce.','This bug doesn''t happen all the time and is hard to reproduce.','''intermittent bug''와 발생 조건(''high concurrency'')을 명시하는 것이 더 정확한 기술적 표현이에요.',false),
  ('developer','고급','버그 수정이 다른 기능에 영향을 주지 않도록 회귀 테스트가 필요하다고 말하고 싶어요.','We should run regression tests to ensure this fix doesn''t introduce any unintended side effects.',NULL,'We need to test that this fix doesn''t break other things.','Testing is needed to make sure the fix is safe.','''regression tests''와 ''unintended side effects''가 품질 관리를 강조하는 전문적인 표현이에요.',false),
  ('developer','고급','이 버그를 재현하기 위한 최소 재현 조건을 정리해달라고 요청하고 싶어요.','Could you put together a minimal reproducible example so we can isolate the issue?',NULL,'Can you show me how to make this bug happen?','Please reproduce the bug and show me the steps.','''minimal reproducible example''이 디버깅 협업에서 사용하는 표준 표현이에요.',false),
  ('developer','기초','API 엔드포인트 명세를 공유해달라고 요청하고 싶어요.','Could you share the API endpoint specs when you get a chance?',NULL,'Please send me the API documentation.','I need the API documentation from you.','''when you get a chance''를 덧붙이면 부드럽게 요청하는 표현이 돼요.',false),
  ('developer','기초','API 응답 형식이 예상과 다르다고 백엔드 개발자에게 알리고 싶어요.','The API response format doesn''t match what''s in the documentation.',NULL,'The API response is not like what I expected.','API response format is wrong compared to my expectation.','''doesn''t match what''s in the documentation''이 API 불일치를 객관적으로 표현하는 방식이에요.',false),
  ('developer','중급','API 인증 방식을 변경해야 한다고 제안하고 싶어요.','I''d suggest migrating the API authentication to OAuth 2.0 for better security.',NULL,'We should change the authentication method of the API.','The API''s current auth method needs to be updated.','구체적인 대안(OAuth 2.0)과 이유(better security)를 포함한 제안이 더 설득력 있어요.',false),
  ('developer','중급','API 호출이 너무 많아서 성능 문제가 생긴다고 설명하고 싶어요.','The number of API calls is causing a performance bottleneck — we should look into batching requests.',NULL,'We are making too many API calls and it''s slow.','Too many API calls are making our app slow.','문제와 해결 방향(''batching requests'')을 함께 제시하는 것이 더 전문적이에요.',false),
  ('developer','중급','API 버전 관리가 필요하다고 팀에 제안하고 싶어요.','I think we should introduce API versioning to maintain backward compatibility.',NULL,'We need to do versioning for our API.','API versioning is important and we should start doing it.','''maintain backward compatibility''가 API 버전 관리의 핵심 이유를 명확히 설명하는 표현이에요.',false),
  ('developer','고급','API 설계 시 멱등성을 보장해야 한다고 설명하고 싶어요.','We need to ensure idempotency for our POST endpoints to prevent duplicate transactions.',NULL,'API requests should give same results when called multiple times.','Calling the API multiple times should not cause problems.','''idempotency''와 구체적인 위험(''duplicate transactions'')을 명시하는 것이 전문적인 API 설계 표현이에요.',false),
  ('developer','고급','API 응답 시간이 SLA를 초과하고 있다고 보고하고 싶어요.','Our API response times are consistently exceeding our 200ms SLA — we need to investigate.',NULL,'Our API is too slow and not meeting requirements.','The API response time is not good enough.','''exceeding our 200ms SLA''처럼 구체적인 수치와 기준을 명시하는 것이 더 전문적이에요.',false),
  ('developer','고급','API 설계 시 하위 호환성을 유지하면서 변경하는 방법을 제안하고 싶어요.','We can introduce breaking changes in a new API version while maintaining the existing endpoints for backward compatibility.',NULL,'We should change the API but not break old clients.','We need to update the API without affecting current users.','''breaking changes in a new version''과 ''backward compatibility''가 API 마이그레이션의 핵심 개념이에요.',false),
  ('developer','고급','외부 API 의존성이 서비스 안정성에 리스크가 된다고 경고하고 싶어요.','Our reliance on this third-party API introduces a single point of failure — we should implement a fallback.',NULL,'Using external API is risky for our service.','External API can cause problems if it goes down.','''single point of failure''와 ''fallback'' 구현 필요성이 시스템 안정성을 논의할 때 핵심 표현이에요.',false),
  ('developer','고급','API 속도 제한을 고려해서 요청 전략을 재설계해야 한다고 말하고 싶어요.','We should redesign our request strategy to stay within the API rate limits and avoid throttling.',NULL,'We need to fix our code because of API rate limits.','Our API calls will be blocked if we don''t handle rate limits.','''redesign request strategy''와 ''avoid throttling''이 API 사용 최적화를 표현하는 전문적인 방식이에요.',false),
  ('developer','기초','이 함수가 무엇을 하는지 팀원에게 간단히 설명하고 싶어요.','This function calculates the user''s score based on their activity.',NULL,'This function is doing the calculation of user score.','The purpose of this function is calculating user score.','동사 중심의 간결한 설명이 코드 설명에서 가장 자연스러운 표현이에요.',false),
  ('developer','기초','이 코드가 왜 이렇게 작성됐는지 배경을 설명하고 싶어요.','I took this approach because the original method had performance issues at scale.',NULL,'I wrote this code like this because of reasons.','This code was written this way for some reasons.','구체적인 이유(''performance issues at scale'')를 포함한 설명이 더 설득력 있어요.',false),
  ('developer','중급','이 디자인 패턴이 왜 여기에 적합한지 설명하고 싶어요.','I chose the Observer pattern here because we need to decouple the event source from its handlers.',NULL,'I used this pattern because it''s good.','This design pattern is used here for decoupling purposes.','패턴 이름과 구체적인 이유를 함께 제시하는 것이 기술 설명의 표준이에요.',false),
  ('developer','중급','이 코드가 아직 완성되지 않았다고 팀원에게 알리고 싶어요.','This is a work in progress — I still need to add error handling and write tests.',NULL,'This code is not finished yet.','I haven''t finished writing this code.','''work in progress''와 남은 작업을 구체적으로 표현하는 것이 협업에서 더 명확해요.',false),
  ('developer','중급','이 부분은 나중에 리팩토링이 필요하다고 주석으로 표시하고 싶다고 말하고 싶어요.','I''ve left a TODO here — this section needs refactoring once we finalize the data model.',NULL,'This part needs to be changed later.','We should refactor this code in the future.','''TODO''와 구체적인 조건을 표현하는 것이 코드 주석 문화에 맞는 표현이에요.',false),
  ('developer','고급','이 비동기 처리 방식이 경쟁 조건을 방지하는 이유를 설명하고 싶어요.','This async approach prevents race conditions by ensuring each operation completes before the next begins.',NULL,'This async code prevents problems with timing.','Using async here avoids timing issues in the code.','''prevents race conditions''과 동작 원리를 명확히 설명하는 것이 더 전문적이에요.',false),
  ('developer','고급','이 추상화 레이어가 왜 필요한지 팀원에게 설명하고 싶어요.','This abstraction layer decouples the business logic from the data access layer, making it easier to test and swap implementations.',NULL,'We need this abstraction layer for good reasons.','This layer separates concerns in our codebase.','추상화의 구체적인 이점(testability, swappability)을 명시하는 것이 더 설득력 있어요.',false),
  ('developer','고급','이 알고리즘의 시간 복잡도를 설명하고 싶어요.','This algorithm runs in O(n log n) time, which is a significant improvement over the previous O(n²) approach.',NULL,'This algorithm is faster than the old one.','The algorithm is more efficient because it''s O(n log n).','이전 복잡도와 비교해서 표현하는 것이 알고리즘 설명에서 가장 명확한 방식이에요.',false),
  ('developer','고급','이 코드의 의존성 주입 패턴을 사용하는 이유를 설명하고 싶어요.','Dependency injection here allows us to mock dependencies in tests and swap implementations without changing the core logic.',NULL,'We use dependency injection here because it''s the right way.','This dependency injection pattern makes our code more flexible.','DI의 실질적인 이점(mocking in tests, swapping implementations)을 구체적으로 설명하는 것이 더 전문적이에요.',false),
  ('developer','고급','이 캐싱 전략이 어떻게 작동하는지 팀원에게 설명하고 싶어요.','We cache the result at the service layer and invalidate it whenever the underlying data changes, keeping the cache fresh without unnecessary DB hits.',NULL,'This caching works by saving data so we don''t need to get it again.','This caching strategy stores data to reduce database queries.','캐시 무효화 전략과 캐시 신선도 유지 방법을 포함한 설명이 더 전문적이에요.',false),
  ('developer','기초','배포 전에 테스트 환경에서 확인해야 한다고 말하고 싶어요.','We should validate this in staging before pushing to production.',NULL,'We need to test this before putting it live.','This should be tested in the test environment first.','''validate in staging before pushing to production''이 배포 프로세스를 표현하는 표준 표현이에요.',false),
  ('developer','기초','이번 릴리즈에 포함될 변경 사항을 팀에 공유하고 싶어요.','Here''s a summary of what''s included in this release.',NULL,'Here are the things we''re releasing today.','These are the changes in today''s release.','''summary of what''s included in this release''가 릴리즈 노트 공유의 표준 표현이에요.',false),
  ('developer','중급','배포 중 롤백이 필요하다고 팀에 긴급히 알리고 싶어요.','We''re seeing critical errors in production — I''m initiating a rollback.',NULL,'We have problems in production and need to go back.','Production is having issues so we need to rollback.','''initiating a rollback''이 긴급 상황에서 롤백을 선언하는 표준 표현이에요.',false),
  ('developer','중급','피처 플래그를 사용해 점진적으로 배포하겠다고 설명하고 싶어요.','We''ll roll this out gradually using feature flags to monitor performance before a full release.',NULL,'We will release this feature slowly to users.','We''re going to deploy this feature step by step.','''feature flags''와 ''roll out gradually''가 점진적 배포를 설명하는 전문적인 표현이에요.',false),
  ('developer','중급','배포 후 모니터링 결과를 팀에 공유하고 싶어요.','Post-deploy metrics look stable — error rates and latency are within normal thresholds.',NULL,'Everything looks okay after deployment.','After the deployment, things seem to be working fine.','구체적인 지표(error rates, latency)를 포함한 배포 후 보고가 더 전문적이에요.',false),
  ('developer','고급','이번 배포가 제로 다운타임으로 진행됐다고 보고하고 싶어요.','The deployment completed with zero downtime using a blue-green deployment strategy.',NULL,'We deployed without any downtime this time.','The release was done successfully with no service interruption.','''zero downtime''과 ''blue-green deployment''가 배포 방식을 전문적으로 설명하는 표현이에요.',false),
  ('developer','고급','이번 릴리즈의 영향을 최소화하기 위해 카나리 배포를 사용하겠다고 제안하고 싶어요.','I''d recommend a canary release — routing 5% of traffic to the new version before a full rollout.',NULL,'We should test this release with some users first before full rollout.','Let''s release to a small percentage of users first to be safe.','''canary release''와 구체적인 트래픽 비율(5%)을 명시하는 것이 더 전문적인 배포 전략 표현이에요.',false),
  ('developer','고급','배포 실패 원인을 분석해 팀에 공유하고 싶어요.','The deployment failed due to a misconfigured environment variable in the production config.',NULL,'The deployment failed because of some configuration problems.','There was a configuration issue that caused the deployment to fail.','실패 원인을 구체적으로 명시(''misconfigured environment variable'')하는 것이 사후 분석의 표준이에요.',false),
  ('developer','고급','다음 배포에서 더 나은 롤백 계획이 필요하다고 제안하고 싶어요.','We should define a clearer rollback plan before our next major release to reduce mean time to recovery.',NULL,'Next time we need a better plan when things go wrong.','We need to prepare for problems in future deployments.','''mean time to recovery''가 서비스 안정성 목표를 표현하는 전문 용어예요.',false),
  ('developer','고급','핫픽스를 바로 프로덕션에 배포해야 한다고 긴급 요청하고 싶어요.','We need to fast-track this hotfix to production — it''s directly impacting user sign-ups.',NULL,'We need to push this fix to production right now.','This bug fix needs to go to production urgently.','''fast-track this hotfix''와 비즈니스 임팩트를 함께 표현하는 것이 긴급 배포 요청에 적합해요.',false),
  ('developer','기초','이 코드가 오래됐고 리팩토링이 필요하다고 말하고 싶어요.','This code is legacy — it would benefit from a refactor.',NULL,'This code is old and needs to be changed.','This old code should be updated soon.','''legacy''와 ''would benefit from a refactor''가 레거시 코드를 지적하는 전문적인 표현이에요.',false),
  ('developer','중급','레거시 코드를 건드리면 예상치 못한 문제가 생길 수 있다고 경고하고 싶어요.','Making changes to this legacy code carries risk — we should add test coverage before touching it.',NULL,'Be careful with this old code because it might break things.','This old code is fragile and changing it may cause problems.','리스크와 선행 조건(test coverage)을 함께 표현하는 것이 더 전문적이에요.',false),
  ('developer','중급','이 기능을 리팩토링하면 성능이 크게 개선될 것이라고 제안하고 싶어요.','Refactoring this module could yield a significant performance improvement and reduce code complexity.',NULL,'Refactoring this will make it faster.','If we refactor this, it will be better.','성능 향상과 코드 복잡도 감소라는 구체적인 이점을 표현하는 것이 더 설득력 있어요.',false),
  ('developer','중급','리팩토링 전에 테스트를 먼저 작성해야 한다고 제안하고 싶어요.','Before refactoring, I''d recommend adding tests to capture the current behavior.',NULL,'We should write tests before we change this code.','Tests need to be written before we start refactoring.','''capture the current behavior''가 리팩토링 전 테스트 작성의 목적을 명확히 표현해요.',false),
  ('developer','고급','이 코드의 기술 부채를 점진적으로 해소하는 전략을 제안하고 싶어요.','I''d recommend a strangler fig approach — gradually replacing legacy components while keeping the system functional.',NULL,'We should fix all the technical debt slowly.','We need to deal with technical debt little by little.','''strangler fig approach''가 레거시 시스템을 점진적으로 교체하는 패턴의 전문 용어예요.',false),
  ('developer','고급','이 레거시 모듈이 현재 시스템의 병목이 되고 있다고 설명하고 싶어요.','This legacy module has become a bottleneck — it''s limiting our ability to scale and ship new features.',NULL,'This old module is causing problems for our whole system.','The legacy module is slowing down our development.','''bottleneck''과 구체적인 영향(scaling, shipping features)을 표현하는 것이 더 설득력 있어요.',false),
  ('developer','고급','이 리팩토링 작업의 범위를 명확히 정의해야 한다고 말하고 싶어요.','Before we start, we should clearly define the scope of this refactor to avoid scope creep.',NULL,'We need to know exactly what we''re refactoring.','The refactoring scope needs to be decided first.','''scope creep''을 방지하기 위한 범위 정의의 중요성을 표현하는 전문적인 방식이에요.',false),
  ('developer','고급','이 레거시 코드를 지금 당장 리팩토링하기보다 비즈니스 가치 기준으로 우선순위를 정해야 한다고 제안하고 싶어요.','Rather than refactoring everything at once, I''d suggest prioritizing by business impact and migration risk.',NULL,'We shouldn''t refactor all legacy code at the same time.','We need to prioritize which legacy code to refactor first.','비즈니스 임팩트와 마이그레이션 리스크를 기준으로 우선순위를 정하는 접근 방식이 더 전략적이에요.',false),
  ('developer','고급','레거시 시스템 마이그레이션 시 데이터 정합성을 검증해야 한다고 강조하고 싶어요.','Data integrity validation is critical during migration — we should run parallel reads to verify consistency.',NULL,'We need to make sure data is correct after migration.','Data needs to be checked before and after migration.','''parallel reads to verify consistency''가 마이그레이션 데이터 정합성 검증의 구체적인 방법을 표현해요.',false),
  ('developer','고급','이 레거시 API를 즉시 제거하지 말고 지원 종료 일정을 공지해야 한다고 제안하고 싶어요.','We should publish a deprecation timeline for this API to give clients time to migrate.',NULL,'We should tell people when we''re going to remove this API.','We can''t remove this API without warning users.','''deprecation timeline''이 API 지원 종료를 전문적으로 공지하는 표준 표현이에요.',false),
  ('developer','기초','README를 업데이트해야 한다고 팀에 말하고 싶어요.','The README needs to be updated to reflect the recent changes.',NULL,'The README needs to be changed.','README is outdated and should be fixed.','''updated to reflect the recent changes''가 문서 업데이트 이유를 명확히 표현해요.',false),
  ('developer','기초','이 함수에 주석이 필요하다고 말하고 싶어요.','This function could use a brief comment explaining the expected input format.',NULL,'This function has no comments and needs some.','Please add comments to explain this function.','주석이 필요한 이유와 내용을 구체적으로 표현하는 것이 더 유용한 피드백이에요.',false),
  ('developer','중급','API 문서가 최신 상태가 아니라고 지적하고 싶어요.','The API documentation is out of date — several endpoints added last sprint aren''t documented yet.',NULL,'The API documentation is wrong and not updated.','API docs are outdated and need to be fixed.','구체적으로 어떤 부분이 누락됐는지 표현하는 것이 더 명확한 피드백이에요.',false),
  ('developer','중급','이 기능의 아키텍처 결정 기록(ADR)을 작성해야 한다고 제안하고 싶어요.','I''d suggest documenting this as an ADR so future engineers understand the context behind this decision.',NULL,'We should write down why we made this architectural decision.','This architectural decision needs to be documented somewhere.','''ADR(Architecture Decision Record)''이 아키텍처 결정을 문서화하는 표준 방식이에요.',false),
  ('developer','중급','온보딩 문서를 개선해서 신규 팀원이 더 빠르게 적응할 수 있도록 하자고 제안하고 싶어요.','I''d like to improve our onboarding docs — it would help new engineers get up to speed faster.',NULL,'The onboarding documents are not good enough for new members.','New team members are having trouble because documentation is poor.','''get up to speed faster''가 온보딩 문서 개선의 목적을 자연스럽게 표현해요.',false),
  ('developer','고급','런북(runbook)을 작성해서 운영 이슈 대응 시간을 줄이자고 제안하고 싶어요.','Creating runbooks for common production issues would help reduce our mean time to resolution.',NULL,'We need documents for when production has problems.','We should have documentation ready for production incidents.','''runbooks''와 ''mean time to resolution''이 운영 문서화의 전문 용어예요.',false),
  ('developer','고급','코드 주석이 왜(Why)보다 무엇(What)을 설명하고 있다고 피드백하고 싶어요.','These comments explain what the code does, but they should focus on why — the code itself already shows the what.',NULL,'Comments in this code are not explaining the right things.','We need better comments that explain the reasoning, not just the actions.','''what vs why in comments''는 코드 주석 품질을 논의하는 핵심 원칙이에요.',false),
  ('developer','고급','기술 문서가 너무 길어서 핵심 내용을 찾기 어렵다고 피드백하고 싶어요.','The documentation is quite verbose — I''d suggest adding a TL;DR section and a quick-start guide.',NULL,'The documentation is too long and hard to read.','Technical docs need to be shorter and easier to navigate.','''TL;DR section''과 ''quick-start guide'' 제안이 문서 개선에 구체적인 방향을 제시해요.',false),
  ('developer','고급','이 코드 변경의 이유를 PR 설명에 명확히 작성해달라고 요청하고 싶어요.','Could you add more context to the PR description — specifically the motivation and the trade-offs considered?',NULL,'Please explain why you made these code changes in the PR.','The PR description needs more explanation about the reasoning.','''motivation and trade-offs considered''가 PR 설명에서 가장 중요한 요소를 명확히 표현해요.',false),
  ('developer','고급','시스템 다이어그램이 현재 아키텍처를 반영하지 못하고 있다고 지적하고 싶어요.','The system architecture diagram is out of sync with the current implementation — we should update it before the next planning cycle.',NULL,'The architecture diagram is wrong and outdated.','Our architecture diagram doesn''t match the actual system anymore.','''out of sync with the current implementation''이 다이어그램 불일치를 표현하는 정확한 방식이에요.',false),
  ('developer','기초','팀원에게 PR 리뷰를 부탁하고 싶어요.','Could you take a look at my PR? It''s ready for review.',NULL,'Please look at my PR when you have time.','My PR needs to be reviewed by someone.','''ready for review''를 명시하면 리뷰 요청 의도가 더 명확해져요.',false),
  ('developer','기초','팀원의 도움이 필요하다고 요청하고 싶어요.','I''m a bit stuck on this — would anyone be available to pair on it?',NULL,'I need someone to help me with this problem.','Can someone help me because I''m having difficulties?','''pair on it''이 협업 요청을 자연스럽게 표현하는 개발자 표현이에요.',false),
  ('developer','중급','PR 리뷰에 시간이 너무 오래 걸린다고 팀에 말하고 싶어요.','Our PR review cycle is a bit slow — would it help to set a 24-hour review SLA?',NULL,'PR reviews are taking too long in our team.','We need faster PR reviews in the team.','문제 제기와 함께 구체적인 해결 제안(24-hour SLA)을 포함하는 것이 더 생산적이에요.',false),
  ('developer','중급','지식 공유 세션을 만들어서 팀 전체 역량을 높이자고 제안하고 싶어요.','I''d like to propose a regular knowledge-sharing session to help level up the team''s understanding of our system.',NULL,'We should share knowledge more in the team.','Team should have more knowledge sharing activities.','''level up the team''s understanding''이 지식 공유의 목적을 자연스럽게 표현해요.',false),
  ('developer','중급','이 작업은 내가 직접 하는 것보다 해당 전문가에게 맡기는 게 낫다고 제안하고 싶어요.','I think this would be better handled by someone with more context on the auth service.',NULL,'I think someone else should do this task.','This task should go to a person who knows this area better.','''someone with more context on X''가 전문성 기반 업무 배분을 정중하게 표현하는 방식이에요.',false),
  ('developer','고급','팀의 온콜 로테이션 구조를 개선해야 한다고 제안하고 싶어요.','Our on-call rotation is leading to burnout — I''d suggest reducing the rotation to two-week cycles and adding better alerting.',NULL,'Our on-call rotation has problems and needs improvement.','The on-call system is too stressful for the team.','문제(burnout)와 구체적인 해결책(two-week cycles, better alerting)을 함께 제시하는 것이 더 설득력 있어요.',false),
  ('developer','고급','팀 간 의존성이 배포 속도를 늦추고 있다고 말하고 싶어요.','Our cross-team dependencies are creating bottlenecks in our release pipeline — we should discuss better decoupling.',NULL,'Too many dependencies between teams is making us slow.','Team dependencies are slowing down our deployments.','''cross-team dependencies''와 ''decoupling''이 팀 간 의존성 문제를 전문적으로 표현하는 용어예요.',false),
  ('developer','고급','이번 인시던트에서 얻은 교훈을 팀 전체와 공유하고 싶어요.','I''d like to share the key learnings from this incident so we can prevent similar issues in the future.',NULL,'Let me share what we learned from this incident.','We should discuss the incident and learn from it.','''key learnings''와 재발 방지 목적을 명시하는 것이 인시던트 회고의 표준 표현이에요.',false),
  ('developer','고급','팀의 코딩 컨벤션을 문서화하고 린터로 자동화하자고 제안하고 싶어요.','I''d suggest formalizing our coding conventions in a shared style guide and enforcing them via linter rules.',NULL,'We should agree on coding standards and make sure everyone follows them.','Team needs consistent coding standards that are automatically checked.','''formalizing in a style guide''와 ''enforcing via linter''가 코딩 컨벤션 자동화의 표준 접근 방식이에요.',false),
  ('developer','고급','팀의 기술 로드맵 계획에 시니어 엔지니어 의견이 더 반영돼야 한다고 말하고 싶어요.','I think senior engineers should be more involved in shaping the technical roadmap early in the planning cycle.',NULL,'Senior engineers should have more say in technical decisions.','The technical roadmap planning should include more senior engineer input.','''involved in shaping the roadmap early''가 시니어 엔지니어 참여의 시점과 방식을 명확히 표현해요.',false),
  ('pm','기초','다음 분기 제품 로드맵을 팀에 공유하고 싶어요.','We''re planning to release the new feature next quarter.',NULL,'We will doing the new feature next quarter.','We will do the new feature next quarter.','''will doing''은 문법적으로 틀린 표현입니다. ''be planning to'' 또는 ''will + 동사원형''으로 써야 합니다.',false),
  ('pm','기초','로드맵 우선순위를 설명하고 싶어요.','This feature takes priority over that one.',NULL,'This feature is more important as that one.','This feature is more important than that one because of business value.','''important as''는 동등 비교이므로 우선순위 맥락에 어울리지 않습니다. ''takes priority over''가 자연스럽습니다.',false),
  ('pm','기초','이번 스프린트 목표를 팀에 설명하고 싶어요.','Our goal for this sprint is to finish the login flow.',NULL,'Our goal of this sprint is finish the login flow.','This sprint, we need finish the login flow.','''goal of''보다 ''goal for''가 자연스럽고, ''is finish''는 ''is to finish''로 써야 합니다.',false),
  ('pm','기초','스프린트 티켓 추정 회의를 시작하고 싶어요.','Let''s estimate the effort for each ticket.',NULL,'Let''s estimate how long tickets are taking.','Let''s figure out how long each ticket will take.','''how long tickets are taking''은 진행 중인 작업을 묻는 뉘앙스입니다. ''estimate the effort''가 추정 회의에 더 적합합니다.',false),
  ('pm','기초','기능 요구사항을 개발팀에 설명하고 싶어요.','The user needs to be able to reset their password.',NULL,'The user needs to able to reset their password.','Users should have the ability to reset passwords.','''to able to''는 문법 오류입니다. ''to be able to''가 올바른 표현입니다.',false),
  ('pm','기초','요구사항이 변경됐음을 팀에 알리고 싶어요.','The requirements have changed since yesterday.',NULL,'The requirements have been changed since yesterday.','We updated the requirements since our last meeting.','''have been changed''는 수동태로 변경의 주체를 숨깁니다. 능동형 ''have changed''가 더 자연스럽습니다.',false),
  ('pm','기초','스테이크홀더에게 진행 상황을 업데이트하고 싶어요.','I want to give you an update on our progress.',NULL,'I want to give you an update about of our progress.','I''d like to share a progress update with you.','''about of''는 문법적으로 틀린 표현입니다. ''update on''이 올바른 표현입니다.',false),
  ('pm','기초','회의 안건을 미리 공유하고 싶어요.','I''ll send the agenda ahead of tomorrow''s meeting.',NULL,'I will send the agenda before the meeting tomorrow.','I''ll share the agenda before we meet tomorrow.','''before the meeting tomorrow''보다 ''ahead of tomorrow''s meeting''이 더 자연스럽고 명확합니다.',false),
  ('pm','기초','어떤 기능을 먼저 개발할지 결정해야 해요.','We should decide which feature to develop first.',NULL,'We should decide which feature to develop it first.','We need to figure out which feature to prioritize.','''to develop it first''에서 ''it''이 불필요하게 중복됩니다. ''to develop first''가 올바릅니다.',false),
  ('pm','기초','백로그에서 가장 중요한 항목을 선택하고 싶어요.','Let''s pick the most important item from the backlog.',NULL,'Let''s pick the most important item from backlog.','Let''s identify the highest-priority item in the backlog.','''from backlog''에는 정관사 ''the''가 필요합니다. ''from the backlog''가 올바릅니다.',false),
  ('pm','기초','이번 달 주요 지표를 팀에 공유하고 싶어요.','Our key metrics for this month look good.',NULL,'Our key metrics for this month are look good.','This month''s key metrics are in good shape.','''are look good''은 문법 오류입니다. ''look good''이 올바릅니다.',false),
  ('pm','기초','DAU 수치가 지난주보다 증가했음을 알리고 싶어요.','DAU increased by 15% compared to last week.',NULL,'DAU is increased by 15% compared to last week.','DAU went up 15% week over week.','''is increased''는 틀린 표현입니다. 수치 변화에는 ''increased''(능동) 또는 ''has increased''(완료)를 씁니다.',false),
  ('pm','기초','회고 회의에서 잘된 점을 언급하고 싶어요.','I think we did a great job this sprint.',NULL,'I think we did a good job in this sprint.','We had a strong sprint this time around.','''a good job in this sprint''보다 ''a great job this sprint''이 더 자연스럽고 격려하는 표현입니다.',false),
  ('pm','기초','다음 스프린트 개선점을 제안하고 싶어요.','We should improve our communication next sprint.',NULL,'We should to improve our communication next sprint.','Let''s work on improving communication in the next sprint.','''should to improve''는 문법 오류입니다. 조동사 뒤에는 동사원형 ''should improve''가 옵니다.',false),
  ('pm','기초','제품 시연을 시작하려고 해요.','Let me show you the new feature we built.',NULL,'Let me to show you the new feature we built.','I''ll walk you through the new feature we built.','''Let me to show''는 문법 오류입니다. ''Let me + 동사원형''이므로 ''Let me show''가 맞습니다.',false),
  ('pm','기초','베타 테스트 결과를 공유하고 싶어요.','The beta test results were very positive.',NULL,'The beta test results was very positive.','We got very positive results from the beta test.','''results was''는 주어-동사 불일치 오류입니다. 복수 주어에는 ''were''를 사용해야 합니다.',false),
  ('pm','기초','사용자 인터뷰 일정을 잡고 싶어요.','Can we schedule an interview with some users?',NULL,'Can we schedule a interview with some users?','Can we set up user interviews for next week?','''a interview''는 모음으로 시작하는 명사 앞에 ''an''을 써야 하므로 ''an interview''가 올바릅니다.',false),
  ('pm','기초','사용자 피드백을 팀과 공유하고 싶어요.','Users are feeling confused about the onboarding flow.',NULL,'Users are feel confused about the onboarding flow.','Users seem confused by the onboarding flow.','''are feel''은 문법 오류입니다. ''are feeling'' 또는 ''feel''이 올바릅니다.',false),
  ('pm','기초','기능 출시 일정을 공유하고 싶어요.','We''re planning to launch the feature this Friday.',NULL,'We''re planning to launch the feature on next Friday.','We''re targeting a Friday launch for this feature.','''on next Friday''는 비자연스럽습니다. ''this Friday'' 또는 ''next Friday'' 단독으로 쓰는 것이 자연스럽습니다.',false),
  ('pm','기초','출시 후 모니터링 계획을 설명하고 싶어요.','We will monitor the launch for any issues.',NULL,'We will monitor the launch for check any issues.','We''ll keep an eye on the launch and watch for issues.','''for check any issues''는 문법 오류입니다. ''for any issues'' 또는 ''to check for any issues''가 올바릅니다.',false),
  ('pm','중급','Q3 로드맵에서 핵심 주제가 사용자 리텐션 개선임을 발표하고 싶어요.','Our main focus for Q3 is improving user retention.',NULL,'Our main focus for Q3 road map is improving the user retention.','The central theme of our Q3 roadmap is boosting user retention.','''road map''은 ''roadmap''으로 붙여 쓰며, ''the user retention''에서 ''the''는 불필요합니다.',false),
  ('pm','중급','로드맵 변경이 비즈니스 목표와 어떻게 연결되는지 설명하고 싶어요.','This change will help us achieve our business goals.',NULL,'This change will contribute to achieve our business goal.','This change directly supports our broader business objectives.','''contribute to achieve''는 ''contribute to achieving'' 또는 ''help achieve''로 써야 합니다.',false),
  ('pm','중급','이해관계자에게 로드맵 아이템의 근거를 설명하고 싶어요.','We included this because it has a high impact on our users.',NULL,'We decided to include this because it has high impact to our users.','We prioritized this item due to its significant impact on user experience.','''impact to''는 ''impact on''이 올바른 표현입니다.',false),
  ('pm','중급','스프린트 범위가 너무 크다고 팀에 말하고 싶어요.','I think we''re overcommitting this sprint.',NULL,'I think we are over-committing in this sprint.','I''m worried we''ve taken on too much this sprint.','''are over-committing in this sprint''보다 ''overcommitting this sprint''이 더 간결하고 자연스럽습니다.',false),
  ('pm','중급','스프린트 목표가 측정 가능해야 한다고 제안하고 싶어요.','Our sprint goal needs to be measurable.',NULL,'Our sprint goal needs to be able to measure.','We should make sure our sprint goal is something we can measure.','''to be able to measure''는 능동 주어를 필요로 합니다. ''measurable''이 올바른 형용사입니다.',false),
  ('pm','중급','기술 부채 티켓도 이번 스프린트에 포함시켜야 한다고 주장하고 싶어요.','We should carve out time for tech debt tickets this sprint.',NULL,'We should include some tech debt tickets in this sprint too.','I''d recommend reserving capacity for a few tech debt items this sprint.','''include some tickets''보다 ''carve out time for''가 계획적 배려를 강조하는 더 자연스러운 표현입니다.',false),
  ('pm','중급','요구사항이 아직 명확하지 않으니 더 논의가 필요하다고 말하고 싶어요.','The requirements aren''t clear enough to move forward with development.',NULL,'The requirements are not clear enough to start developing.','We need more clarity on the requirements before we can start building.','''start developing''보다 ''move forward with development''가 더 격식체이며 PM 맥락에 적합합니다.',false),
  ('pm','중급','엣지 케이스가 명세서에 빠져있다고 지적하고 싶어요.','We didn''t account for the edge cases in the spec.',NULL,'We forgot to mention the edge case in the spec.','A few edge cases seem to be missing from the spec.','''forgot to mention''은 실수를 인정하는 표현이고, ''didn''t account for''는 고려하지 못했음을 객관적으로 말하는 표현입니다.',false),
  ('pm','중급','범위 외 기능이 포함되었다고 팀에 알리고 싶어요.','This feature falls outside the scope of this sprint.',NULL,'This feature is not in the scope of this sprint.','This feature is out of scope for the current sprint.','''not in the scope''보다 ''falls outside the scope'' 또는 ''out of scope''가 더 자연스러운 전문 표현입니다.',false),
  ('pm','중급','임원에게 지연 이유를 설명하고 싶어요.','We''re behind schedule due to an unexpected technical issue.',NULL,'We are behind schedule due to the unexpected technical issue.','We''ve hit an unexpected technical snag that''s pushed back our timeline.','''the unexpected technical issue''에서 불특정 이슈이므로 ''an''이 맞습니다.',false),
  ('pm','중급','스테이크홀더의 새 기능 요청을 다음 분기로 미루고 싶어요.','We''ll revisit your request next quarter.',NULL,'We will think about your request for next quarter.','I''ll add your request to our Q3 backlog for consideration.','''think about''은 모호한 표현입니다. ''revisit''이 다음 분기에 구체적으로 재검토하겠다는 의지를 전달합니다.',false),
  ('pm','중급','경영진에게 리소스 추가 요청을 하고 싶어요.','We need additional resources to deliver this on time.',NULL,'We need more resource to deliver this on time.','To hit this deadline, we''ll need to bring in additional resources.','''more resource''는 ''more resources''(복수) 또는 ''additional resources''가 자연스럽습니다.',false),
  ('pm','중급','영향도와 작업량 기준으로 기능 우선순위를 정하고 싶어요.','Let''s prioritize based on impact versus effort.',NULL,'Let''s prioritize by impact versus effort.','I suggest we rank features by their impact-to-effort ratio.','''prioritize by''도 가능하지만, ''prioritize based on''이 기준을 명시할 때 더 격식체입니다.',false),
  ('pm','중급','이 기능이 핵심 사용자 가치를 제공하지 않아 보류해야 한다고 설명하고 싶어요.','This feature doesn''t deliver core user value, so I''d recommend pushing it back.',NULL,'This feature doesn''t provide core value so we should delay it.','Since this doesn''t address a core user need, let''s defer it for now.','''delay''는 단순 연기이고, ''push it back''은 일정 조정의 뉘앙스로 더 자연스럽습니다.',false),
  ('pm','중급','긴급한 버그 수정이 신규 기능보다 우선되어야 한다고 주장하고 싶어요.','The bug fix is more urgent than shipping new features.',NULL,'The bug fix is more urgent than adding new feature.','We should address the critical bug before moving on to new feature work.','''adding new feature''보다 ''shipping new features''가 제품 배포 맥락에 더 자연스럽습니다.',false),
  ('pm','중급','전환율이 목표 대비 낮다는 것을 보고하고 싶어요.','Our conversion rate is falling short of our target.',NULL,'Our conversion rate is lower than our target.','We''re not hitting our conversion rate target — we''re about 10% below.','''lower than''은 사실 전달이고, ''falling short of''는 목표 달성 실패를 강조하는 자연스러운 표현입니다.',false),
  ('pm','중급','지표 하락의 원인을 분석해야 한다고 제안하고 싶어요.','We need to investigate why our metrics have dropped.',NULL,'We need to analyze why our metrics have been dropped.','Let''s dig into what''s driving the drop in our metrics.','''have been dropped''는 수동태 오용입니다. 자연 하락에는 능동형 ''have dropped''를 씁니다.',false),
  ('pm','중급','A/B 테스트 결과가 통계적으로 유의미하다고 설명하고 싶어요.','The A/B test results are statistically significant.',NULL,'The A/B test result is statistically meaning.','We have statistically significant results from the A/B test.','''statistically meaning''은 잘못된 표현입니다. ''statistically significant''가 올바른 전문 표현입니다.',false),
  ('pm','중급','팀이 이번 스프린트에서 좋은 협업을 보여줬다고 칭찬하고 싶어요.','The team showed great collaboration this sprint.',NULL,'Everyone worked well together in this sprint.','I really appreciated how well everyone collaborated this sprint.','''worked well together''는 자연스럽지만, ''showed great collaboration''이 성과를 강조하는 더 격식있는 표현입니다.',false),
  ('pm','중급','반복되는 커뮤니케이션 문제를 회고에서 다루고 싶어요.','We ran into communication issues again this sprint.',NULL,'Communication problem happened again this sprint.','We''re seeing a recurring pattern of communication breakdowns this sprint.','''problem happened''는 단순 서술이고, ''ran into issues''가 겪었음을 표현하는 더 자연스러운 구어체입니다.',false),
  ('pm','중급','회고에서 팀 프로세스 개선을 위한 액션 아이템을 정하고 싶어요.','Let''s define action items to improve our team process.',NULL,'Let''s make action items to improve our process.','I''d like us to walk away from this retro with clear action items.','''make action items''보다 ''define action items''가 더 격식있고 목적을 명확히 합니다.',false),
  ('pm','중급','신규 기능이 사용자 목표에 얼마나 잘 맞는지 설명하고 싶어요.','This feature closely aligns with what users are trying to accomplish.',NULL,'This feature is very aligned with user needs.','The feature maps well to our users'' core jobs-to-be-done.','''is very aligned''보다 ''closely aligns with''가 더 능동적이고 자연스러운 표현입니다.',false),
  ('pm','중급','제품 리뷰에서 UX 문제점을 지적하고 싶어요.','There are some UX issues we need to address.',NULL,'There are some UX problem we need to fix.','I noticed a few UX pain points that need to be resolved.','''some UX problem''은 복수형 오류입니다. ''UX issues'' 또는 ''UX problems''가 올바릅니다.',false),
  ('pm','중급','이 기능이 예상보다 더 좋은 결과를 냈다고 공유하고 싶어요.','This feature performed better than expected.',NULL,'This feature performed more better than we expected.','The feature outperformed our initial expectations.','''more better''는 이중 비교급 오류입니다. ''performed better than expected''가 올바릅니다.',false),
  ('pm','중급','사용자 인터뷰에서 발견한 주요 인사이트를 팀에 공유하고 싶어요.','Our user interviews surfaced some key insights.',NULL,'From user interviews, we found many interesting things.','We pulled a few meaningful insights from the user interviews.','''found many interesting things''는 모호합니다. ''surfaced key insights''가 더 전문적이고 명확합니다.',false),
  ('pm','중급','사용자 피드백이 우리 가정을 검증했다고 말하고 싶어요.','The user feedback validated our assumptions.',NULL,'The user feedback proved our assumption was right.','User feedback confirmed that our initial assumptions were on the right track.','''proved our assumption was right''도 가능하지만, ''validated our assumptions''가 UX 리서치 맥락에서 더 전문적입니다.',false),
  ('pm','중급','사용자 불만 패턴이 반복되고 있음을 설명하고 싶어요.','We''re seeing a recurring pattern of user complaints.',NULL,'Users are always complaining about the same issue.','Users keep running into the same friction points.','''always complaining''은 다소 부정적 뉘앙스입니다. ''recurring pattern''이 더 객관적이고 분석적입니다.',false),
  ('pm','중급','소프트 론칭 후 문제가 발견되면 즉시 롤백할 것이라고 말하고 싶어요.','If we see any issues, we''ll roll back the feature immediately.',NULL,'If we see any issue, we will rollback the feature immediately.','We''re prepared to roll back immediately if any critical issues surface post-launch.','''rollback''은 명사이고, 동사로는 ''roll back''(두 단어)이 올바릅니다.',false),
  ('pm','중급','피처 플래그로 점진적 출시를 계획하고 있다고 설명하고 싶어요.','We''re planning a phased rollout using feature flags.',NULL,'We plan to release it slowly using feature flag.','We''ll use feature flags to control the gradual rollout.','''release it slowly''보다 ''phased rollout''이 점진적 출시를 더 전문적으로 표현합니다.',false),
  ('pm','중급','출시 후 첫 48시간 동안 지표를 긴밀히 모니터링하겠다고 알리고 싶어요.','We''ll keep a close eye on key metrics in the first 48 hours post-launch.',NULL,'We will closely watch the metrics after the launch.','Our team will be actively monitoring metrics for the 48 hours following launch.','''watch the metrics after the launch''은 모호합니다. ''48 hours post-launch''처럼 구체적인 시간 범위를 명시하는 것이 더 명확합니다.',false),
  ('pm','중급','경쟁사 분석 결과를 팀에 공유하고 싶어요.','Competitors are gaining ground in this space.',NULL,'Our competitor is doing well in this area.','Our competitive analysis shows rivals are moving fast here.','''doing well''은 너무 막연합니다. ''gaining ground''가 경쟁 우위가 좁혀지고 있다는 더 명확한 표현입니다.',false),
  ('pm','중급','MVP 범위를 팀과 합의하고 싶어요.','Let''s align on which features should be included in the MVP.',NULL,'Let''s agree what features should be in the MVP.','We need to reach consensus on the MVP scope before moving forward.','''agree what features''보다 ''align on which features''가 협의 과정을 강조하는 더 자연스러운 표현입니다.',false),
  ('pm','중급','이 기능이 왜 핵심 사용자 문제를 해결하는지 설명하고 싶어요.','This feature directly addresses a core user pain point.',NULL,'This feature will solve the user''s problem.','By solving this problem, we''re tackling one of our users'' biggest frustrations.','''solve the user''s problem''은 막연합니다. ''addresses a core user pain point''가 더 구체적이고 제품 언어로 자연스럽습니다.',false),
  ('pm','중급','팀이 제품 비전을 이해하고 있는지 확인하고 싶어요.','Is everyone aligned on our product vision?',NULL,'Does everyone understand what we are trying to achieve?','I want to make sure we''re all on the same page about where we''re headed.','''understand what we are trying to achieve''는 길고 informal합니다. ''aligned on our product vision''이 더 간결하고 전문적입니다.',false),
  ('pm','중급','이번 스프린트에서 가장 큰 기술적 리스크를 팀에 알리고 싶어요.','The biggest technical risk this sprint is the database migration.',NULL,'The biggest technical risk is the database migration.','Our main technical concern going into this sprint is the database migration.','시점을 명시하는 ''this sprint''를 추가하면 더 명확해집니다.',false),
  ('pm','중급','고객 이탈률이 증가하고 있어 빠른 대응이 필요하다고 말하고 싶어요.','Our churn rate is climbing, and we need to act quickly.',NULL,'Our churn rate is going up and we need to do something.','Churn is trending upward — we need to get ahead of this fast.','''going up and do something''은 모호합니다. ''climbing''과 ''act quickly''가 긴박함을 더 잘 전달합니다.',false),
  ('pm','중급','다음 릴리즈에서 기술 부채를 줄이는 것이 목표라고 말하고 싶어요.','We''re aiming to reduce technical debt in the next release.',NULL,'We want to decrease our technical debt in next release.','Our goal for the upcoming release is to pay down some of our technical debt.','''decrease''보다 ''reduce''가, ''in next release''보다 ''in the next release''가 더 자연스럽습니다.',false),
  ('pm','중급','사용자 리서치 없이 가정을 검증하기 어렵다고 설명하고 싶어요.','Without user research, it''s hard to validate our assumptions.',NULL,'Without user research, we can''t check if our assumption is correct.','We can''t confidently move forward without validating these assumptions through research.','''check if our assumption is correct''은 너무 직접적입니다. ''validate our assumptions''가 더 전문적입니다.',false),
  ('pm','중급','이번 분기 OKR 달성률을 보고하고 싶어요.','We hit most of our OKR targets this quarter.',NULL,'We achieved most of our OKR this quarter.','We''re tracking at about 80% completion on our Q2 OKRs.','''achieved our OKR''보다 ''hit our OKR targets''가 목표 달성을 더 명확히 표현합니다.',false),
  ('pm','중급','신규 기능 출시가 고객 만족도에 긍정적인 영향을 미쳤다고 말하고 싶어요.','Customer satisfaction has improved since the new feature launch.',NULL,'Customers are more satisfying after the new feature launch.','We''ve seen a meaningful uptick in customer satisfaction following the launch.','''more satisfying''은 형용사 오용입니다. ''satisfaction has improved''가 올바른 표현입니다.',false),
  ('pm','중급','내부 테스트에서 성능 저하가 발견됐다고 알리고 싶어요.','We identified performance issues during internal testing.',NULL,'We found some performance issue during internal testing.','Internal testing surfaced some performance degradation we need to address.','''some performance issue''는 복수형 오류입니다. ''performance issues''가 올바르고, ''identified''가 더 전문적입니다.',false),
  ('pm','중급','다음 분기에 모바일 앱 리뉴얼을 계획하고 있다고 말하고 싶어요.','We''re planning a mobile app redesign for next quarter.',NULL,'We are planning to redesign the mobile app next quarter.','We''ve scoped a mobile app redesign as a key initiative for Q3.','''planning to redesign''보다 ''planning a redesign''이 더 자연스러운 명사구 표현입니다.',false),
  ('pm','중급','기능 요청이 현재 전략과 맞지 않는다고 설명하고 싶어요.','This feature request isn''t aligned with our current strategy.',NULL,'This feature request doesn''t match our current strategy.','This request falls outside our current strategic focus.','''doesn''t match''보다 ''isn''t aligned with''가 전략적 맥락에서 더 자연스럽습니다.',false),
  ('pm','고급','장기 제품 비전과 단기 실행 계획이 어떻게 연결되는지 임원에게 설명하고 싶어요.','Our long-term vision is grounded in short-term bets that deliver user value.',NULL,'Our long-term vision connects with short-term plan by focusing on user value.','Each near-term initiative is intentionally sequenced to build toward our three-year product vision.','''connects with''는 연결이 모호합니다. ''grounded in''이 단기 실행이 장기 비전의 토대임을 더 잘 표현합니다.',false),
  ('pm','고급','스프린트 속도가 추정치와 다를 때 팀에게 원인을 설명하고 싶어요.','Our velocity deviated from our estimates this sprint.',NULL,'Our velocity is different from our estimation this sprint.','We saw a significant variance between our estimated and actual velocity this sprint.','''different from estimation''은 평이합니다. ''deviated from estimates''가 속도 차이를 더 정밀하게 표현합니다.',false),
  ('pm','고급','모호한 요구사항이 개발 후반에 리스크를 초래할 수 있다고 경고하고 싶어요.','Ambiguous requirements will introduce risk late in the development cycle.',NULL,'Vague requirements will cause problems later in development.','Leaving requirements underspecified now will likely surface as costly rework downstream.','''cause problems''는 막연합니다. ''introduce risk late in the cycle''이 리스크 관리 언어로 더 적합합니다.',false),
  ('pm','고급','스테이크홀더의 기대치를 조기에 조율하지 않으면 갈등이 생길 수 있다고 설명하고 싶어요.','Failure to align stakeholder expectations early can lead to friction down the road.',NULL,'If we don''t align stakeholders early, conflict will happen.','Misaligned expectations tend to create costly conflict if not addressed upfront.','''conflict will happen''은 단순 예측입니다. ''lead to friction down the road''가 결과를 더 세련되게 표현합니다.',false),
  ('pm','고급','사용자 영향도, 전략적 적합성, 실현 가능성 세 가지 기준으로 백로그를 점수화하겠다고 설명하고 싶어요.','We''ll evaluate the backlog across three dimensions: user impact, strategic fit, and feasibility.',NULL,'We''ll score the backlog using impact, strategy fit, and feasibility.','I propose we score each backlog item on impact, strategic alignment, and technical feasibility.','''impact, strategy fit''보다 ''user impact, strategic fit, and feasibility''처럼 세 항목을 명확히 나열하는 것이 더 정확합니다.',false),
  ('pm','고급','코호트 분석 결과 7일 리텐션이 신규 유저에서 낮다는 것을 발표하고 싶어요.','Cohort analysis reveals that day-7 retention is significantly lower among new users.',NULL,'Our cohort analysis shows new users have low retention after 7 days.','Our cohort data shows a sharp retention drop-off at day 7, concentrated in new user segments.','''shows new users have low retention after 7 days''는 어색합니다. ''day-7 retention is lower among new users''가 더 데이터 분석 맥락에 정확합니다.',false),
  ('pm','고급','이번 스프린트 실패가 프로세스 문제이지 사람 문제가 아님을 강조하고 싶어요.','This sprint''s shortfall points to a process gap, not a people issue.',NULL,'The sprint failure was caused by the process, not people.','The root cause here is a systemic process failure — not individual performance.','''caused by the process, not people''은 직설적입니다. ''process gap, not a people issue''가 더 건설적이고 심리적 안정성을 높이는 표현입니다.',false),
  ('pm','고급','제품이 시장에서 차별화 포인트를 잃고 있다고 임원에게 경고하고 싶어요.','Our product is losing its competitive differentiation.',NULL,'Our product is losing its differentiation in the market.','We risk eroding our market differentiation if we don''t act on this soon.','''in the market''은 중복 표현입니다. ''competitive differentiation''이 더 정확하며, ''risk eroding''이 긴박함을 전달합니다.',false),
  ('pm','고급','사용자 인터뷰에서 나온 인사이트가 기존 가정을 완전히 뒤집었다고 공유하고 싶어요.','The user interviews fundamentally challenged our core assumptions.',NULL,'The user interviews showed our assumptions were completely wrong.','Our assumptions were invalidated by the user research — we need to rethink the approach.','''completely wrong''은 너무 단정적입니다. ''fundamentally challenged''가 데이터 기반으로 가정을 재검토해야 함을 더 전문적으로 표현합니다.',false),
  ('pm','고급','출시 전 리스크 매트릭스를 검토하고 잠재적 차단 요소를 확인하고 싶어요.','Before launch, let''s review the risk matrix and identify any potential blockers.',NULL,'Before launch, we should check if there are any risks.','I''d like to walk through our pre-launch risk matrix to surface any critical blockers.','''check if there are any risks''는 너무 일반적입니다. ''review the risk matrix and identify blockers''가 론칭 전 체계적인 절차를 명확히 표현합니다.',false),
  ('pm','고급','제품 지표와 비즈니스 지표 간의 상관관계를 임원진에게 설명하고 싶어요.','Improvements in our product metrics tend to correlate with stronger business outcomes.',NULL,'Better product metrics lead to better business metrics.','We''ve established a clear correlation between product health metrics and downstream revenue impact.','''lead to better business metrics''는 인과를 단정합니다. ''correlate with''가 데이터 분석에서 더 정확한 표현입니다.',false),
  ('pm','고급','여러 팀 간 의존성을 해결하지 않으면 출시가 지연될 것임을 경고하고 싶어요.','Unresolved cross-team dependencies are a critical risk to our launch timeline.',NULL,'If we don''t fix dependencies between teams, we''ll be late.','Without resolving these inter-team dependencies, we''re looking at a significant timeline slip.','''fix dependencies''는 모호합니다. ''unresolved cross-team dependencies''가 문제의 본질을 더 정확히 표현합니다.',false),
  ('pm','고급','신규 기능이 기존 수익화 모델과 어떻게 연계되는지 설명하고 싶어요.','This feature is designed to support our existing monetization strategy.',NULL,'This new feature will help our monetization.','The feature is directly tied to our core monetization model and should drive premium conversions.','''help our monetization''은 막연합니다. ''support our monetization strategy''가 전략적 연계를 더 명확히 표현합니다.',false),
  ('pm','고급','기능 개발 전에 사용자 리서치를 더 해야 한다고 팀을 설득하고 싶어요.','We''d benefit from deeper user research before committing to a build direction.',NULL,'We should do more research before we start building.','Investing in further discovery now will reduce the risk of building the wrong thing.','''do more research before building''은 소극적입니다. ''deeper research before committing''이 결정 이전의 검증 필요성을 더 설득력 있게 표현합니다.',false),
  ('pm','고급','시장 환경 변화로 기존 전략을 재검토해야 한다고 경영진에게 제안하고 싶어요.','Shifting market dynamics call for a reassessment of our current strategy.',NULL,'The market is changing so we should change our strategy.','Given the evolving competitive landscape, I recommend we revisit our strategic assumptions.','''market is changing so we should change''는 너무 단순합니다. ''shifting market dynamics call for a reassessment''가 더 격식있는 전략 언어입니다.',false),
  ('pm','고급','현재 제품 방향이 사용자 니즈보다 내부 편의에 맞춰져 있다고 지적하고 싶어요.','Our current product direction seems to be optimized for internal convenience rather than user needs.',NULL,'I think our product is being built for our convenience, not for users.','We''ve been building for operational efficiency rather than solving real user problems.','''built for our convenience''는 다소 직접적입니다. ''optimized for internal convenience rather than user needs''가 더 객관적이고 설득력 있는 표현입니다.',false),
  ('pm','고급','데이터 기반 결정 문화를 팀에 정착시켜야 한다고 주장하고 싶어요.','We need to embed a data-driven decision-making culture across the team.',NULL,'We should use data more when we make decisions.','Building a culture where decisions are grounded in data, not instinct, is critical to our growth.','''use data more''는 지나치게 단순합니다. ''embed a data-driven culture''가 조직 수준의 변화를 강조합니다.',false),
  ('pm','고급','출시 후 사용자 세그먼트별로 성과 차이를 분석하고 싶다고 말하고 싶어요.','Post-launch, we''ll analyze performance variances across user segments.',NULL,'After launch, we''ll look at how different users performed.','Our post-launch analysis will break down outcomes by user segment to surface differential impacts.','''how different users performed''는 막연합니다. ''performance variances across user segments''가 분석 목적을 더 명확히 표현합니다.',false),
  ('pm','고급','기술 파트너와의 통합이 로드맵 일정에 의존성을 만든다고 설명하고 싶어요.','The partner integration introduces external dependencies that could affect our roadmap timeline.',NULL,'The integration with our tech partner depends on their schedule.','Our roadmap is exposed to schedule risk because of the dependency on the third-party integration.','''depends on their schedule''은 단순 서술입니다. ''introduces external dependencies''가 리스크 관리 관점에서 더 전문적입니다.',false),
  ('pm','고급','사용자 확보보다 유지가 현재 단계에서 더 중요한 전략임을 주장하고 싶어요.','At this stage, retention is a higher-leverage strategy than acquisition.',NULL,'Keeping users is more important than getting new users right now.','Given where we are in the growth curve, optimizing for retention will yield better returns than acquisition.','''keeping users is more important''은 너무 단순합니다. ''retention is a higher-leverage strategy''가 투자 대비 효과를 강조하는 더 전략적인 표현입니다.',false),
  ('pm','중급','팀원에게 명확한 업무 우선순위를 전달하고 싶어요.','Please prioritize the most critical task first.',NULL,'Please work on the most important task at first.','Let''s make sure everyone is focused on the highest-priority work.','''at first''는 ''처음에''라는 의미로 맥락에 맞지 않습니다. ''first'' 단독 또는 ''prioritize''를 쓰는 것이 자연스럽습니다.',false),
  ('pm','중급','다음 기능의 성공 지표를 미리 정해두고 싶어요.','We need to define success metrics before we start.',NULL,'We need to define success metric before we start.','Let''s agree on what success looks like before we kick off development.','''success metric''은 복수형 ''success metrics''가 일반적이며, ''agree on what success looks like''가 팀 협의 맥락에 자연스럽습니다.',false),
  ('pm','중급','이번 분기 신규 기능이 예상보다 늦어질 것 같다고 알리고 싶어요.','The new feature will be delivered later than expected.',NULL,'The new feature will be delivered more late than expected.','We''re tracking behind schedule on the new feature — expect a delay of about one week.','''more late''는 문법 오류입니다. 비교급은 ''later''입니다.',false),
  ('pm','중급','제품 피드백 루프를 짧게 유지해야 한다고 팀에 설명하고 싶어요.','We should shorten our feedback loop with users.',NULL,'We should get feedback from users faster.','Tightening the feedback loop will help us course-correct before we invest too deeply.','''get feedback faster''보다 ''shorten our feedback loop''이 프로세스 개선을 더 명확히 표현합니다.',false),
  ('pm','중급','이번 릴리즈에서 성능 최적화가 UX 개선보다 우선이라고 설명하고 싶어요.','For this release, performance optimization takes precedence over UX improvements.',NULL,'Performance is more important than UX improvement for this release.','Given the current stability issues, we''re prioritizing performance over UX work this cycle.','''more important than''보다 ''takes precedence over''가 우선순위 결정을 더 전문적으로 표현합니다.',false),
  ('pm','중급','팀 전체가 같은 제품 목표를 향하고 있는지 확인하고 싶어요.','I want to make sure everyone is aligned on our product goals.',NULL,'I want to check if everyone has the same product goal.','Let''s take a moment to confirm we''re all pulling in the same direction.','''has the same goal''은 단순 소유 표현입니다. ''aligned on''이 팀 정렬을 더 적절히 나타냅니다.',false),
  ('pm','중급','고객 지원팀에서 올라온 이슈를 다음 스프린트에 반영하고 싶어요.','We should incorporate the customer support issues into the next sprint.',NULL,'We should put the customer support issues into next sprint.','I''d like to fold in the top customer support issues when we plan the next sprint.','''put into next sprint''보다 ''incorporate into the next sprint''이 더 격식체이며 자연스럽습니다.',false),
  ('pm','고급','제품 로드맵이 기술 역량 한계를 감안해 현실적으로 설계되어야 한다고 주장하고 싶어요.','Our roadmap needs to be calibrated against our actual engineering capacity.',NULL,'Our roadmap should be realistic about what we can actually build.','A credible roadmap must account for our current technical constraints and team bandwidth.','''realistic about what we can build''은 일상 표현입니다. ''calibrated against engineering capacity''가 더 전문적인 계획 언어입니다.',false),
  ('pm','고급','제품 전략이 단기 매출보다 장기 사용자 가치에 집중해야 한다고 설득하고 싶어요.','Our product strategy should optimize for long-term user value over short-term revenue gains.',NULL,'We should focus on user value, not just short-term revenue.','Sacrificing long-term user value for near-term revenue will erode trust and ultimately hurt growth.','''focus on user value''보다 ''optimize for long-term user value over short-term revenue''가 전략 방향을 더 명확히 제시합니다.',false),
  ('pm','고급','플랫폼 확장 전에 핵심 기능의 안정성을 확보해야 한다고 임원에게 설명하고 싶어요.','Before scaling the platform, we need to ensure core feature stability.',NULL,'Before expanding the platform, we need to make the core features stable.','Expanding prematurely without solidifying the core will create compounding technical and UX debt.','''make the core features stable''은 직접적이지만 평이합니다. ''ensure core feature stability''가 더 전문적입니다.',false),
  ('pm','고급','사용자 획득 채널별 LTV를 비교해서 마케팅 예산 배분을 최적화해야 한다고 제안하고 싶어요.','We should compare LTV across acquisition channels to optimize our marketing spend.',NULL,'We should compare how much value users from different channels bring.','Analyzing LTV by acquisition channel will allow us to reallocate budget toward the highest-value cohorts.','''compare value from different channels''은 막연합니다. ''compare LTV across acquisition channels''가 더 정확한 분석 언어입니다.',false),
  ('pm','고급','다음 분기 전략 방향을 결정하기 전에 시장 조사를 충분히 해야 한다고 주장하고 싶어요.','We should conduct thorough market research before committing to a strategic direction.',NULL,'We should do enough market research before deciding strategy.','Locking in a strategic direction without adequate market validation increases our risk of misalignment.','''do enough market research''은 단순한 표현입니다. ''conduct thorough market research before committing''이 더 전략적이고 격식있는 표현입니다.',false),
  ('pm','고급','사용자 세그먼트마다 다른 온보딩 플로우가 필요하다고 설명하고 싶어요.','Different user segments require tailored onboarding experiences.',NULL,'Different users need different onboarding flows.','A one-size-fits-all onboarding approach will underserve segments with distinct needs and contexts.','''different users need different flows''는 너무 단순합니다. ''tailored onboarding experiences''가 개인화 전략을 더 명확히 표현합니다.',false),
  ('pm','고급','이 기능이 핵심 사용자층에게 불균형적으로 높은 가치를 제공한다고 설명하고 싶어요.','This feature delivers disproportionate value to our core user segment.',NULL,'This feature is very valuable for our core users.','The value concentration in our power-user segment makes this a high-leverage investment.','''very valuable for core users''는 막연합니다. ''delivers disproportionate value''가 투자 대비 효과의 불균형을 더 정밀하게 표현합니다.',false),
  ('pm','고급','팀이 작은 실험을 빠르게 반복하는 문화를 만들어야 한다고 주장하고 싶어요.','We need to build a culture of rapid, small-scale experimentation.',NULL,'Our team should try small experiments more quickly.','Institutionalizing a test-and-learn mindset will help us make faster, more confident product decisions.','''try small experiments more quickly''는 단순합니다. ''culture of rapid experimentation''이 조직 문화 변화를 더 명확히 강조합니다.',false),
  ('pm','고급','현재 제품 지표가 표면적 성장만 반영하고 진짜 사용자 가치는 보여주지 않는다고 지적하고 싶어요.','Our current metrics capture surface-level growth but don''t reflect true user value.',NULL,'Our metrics only show growth but not real user value.','Vanity metrics may show growth, but they obscure whether we''re actually solving the right problems.','''only show growth but not real value''는 단순합니다. ''surface-level growth vs. true user value''가 허상 지표(vanity metrics) 문제를 더 명확히 드러냅니다.',false),
  ('pm','고급','제품-시장 적합성 검증 전에 성장에 투자하는 것은 시기상조라고 설득하고 싶어요.','Investing heavily in growth before achieving product-market fit is premature.',NULL,'We shouldn''t spend a lot on growth before we know our product works.','Scaling before validating product-market fit risks amplifying a broken model rather than a working one.','''spend a lot on growth before knowing it works''는 구어체입니다. ''investing in growth before product-market fit''이 더 전략적인 언어입니다.',false);
